int bpnn_train_kernel(BPNN *net, float *eo, float *eh)
{
  int in, hid, out;
  float out_err, hid_err;
  in = net->input_n;
  hid = net->hidden_n;
  out = net->output_n;

  printf("Performing CPU computation\n");

  float *input_weights_one_dim;
  float *input_weights_prev_one_dim;
  float *partial_sum;
  float sum;
  int num_blocks = in / BLOCK_SIZE;

  input_weights_one_dim = (float *) malloc((in + 1)* (hid + 1) * sizeof(float));
  input_weights_prev_one_dim = (float *) malloc((in + 1)* (hid + 1) * sizeof(float));
  partial_sum = (float *) malloc(num_blocks * WIDTH * sizeof(float));

  int m = 0;
  for (int k = 0; k <= in; k++) {
    for (int j = 0; j <= hid; j++) {
      input_weights_one_dim[m] = net->input_weights[k][j];
      input_weights_prev_one_dim[m] = net->input_prev_weights[k][j];
      m++;
    }
  }

  omp_set_num_threads(NUM_THREAD);
  #pragma omp parallel for shared(input_weights_one_dim, net, in, hid, partial_sum, num_blocks) private(m, k, j, sum) schedule(static)
  for (int by = 0; by < num_blocks; by++) {
    for (int ty = 0; ty < HEIGHT; ty++) {
      int index_in = HEIGHT * by + ty + 1;
      float input_node_val = net->input_units[index_in];

      float local_sum = 0.0;
      for (int tx = 0; tx < WIDTH; tx++) {
        int index = (hid + 1) * HEIGHT * by + (hid + 1) * ty + tx + 1 + (hid + 1);
        float w_val = input_weights_one_dim[index];
        float product = w_val * input_node_val;

        float tree_sum = product;
        for (int i = 1; i <= HEIGHT; i = i * 2) {
          int power_two = i;
          if (ty % power_two == 0) {
            int partner_idx = (ty + power_two/2);
            if (partner_idx < HEIGHT) {
              int partner_index = (hid + 1) * HEIGHT * by + (hid + 1) * partner_idx + tx + 1 + (hid + 1);
              tree_sum += input_weights_one_dim[partner_index];
            }
          }
        }
        if (ty % (HEIGHT/2) == 0 && ty < HEIGHT/2) { 
           local_sum += tree_sum;
        }
      }

      if (ty == 0) {
         for(int tx=0; tx<WIDTH; tx++) {
            int idx = (hid + 1) * HEIGHT * by + (hid + 1) * ty + tx + 1 + (hid + 1);
            input_weights_one_dim[idx] = local_sum; 
         }
         partial_sum[by * hid + ty] = local_sum;
      }
    }
  }

  for (int j = 1; j <= hid; j++) {
    sum = 0.0;
    for (int k = 0; k < num_blocks; k++) {
      sum += partial_sum[k * hid + j-1];
    }
    sum += net->input_weights[0][j];
    net->hidden_units[j] = squash(sum);
  }

  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
  bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
  bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, &hid_err);
  bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);

  #pragma omp parallel for shared(input_weights_one_dim, input_weights_prev_one_dim, net, hid, delta, ly, in) private(j, k, new_dw) schedule(static)
  for (int by = 0; by < num_blocks; by++) {
    for (int ty = 0; ty < HEIGHT; ty++) {
      for (int tx = 0; tx < WIDTH; tx++) {
        int index = (hid + 1) * HEIGHT * by + (hid + 1) * ty + tx + 1 + (hid + 1);
        int index_y = HEIGHT * by + ty + 1;
        int index_x = tx + 1;

        float delta_val = net->hidden_delta[index_x];
        float ly_val = net->input_units[index_y];
        float oldw_val = input_weights_prev_one_dim[index];

        float new_dw = ((ETA * delta_val * ly_val) + (MOMENTUM * oldw_val));
        input_weights_one_dim[index] += new_dw;
        input_weights_prev_one_dim[index] = new_dw;

        if (ty == 0 && by == 0) {
          float oldw_x = input_weights_prev_one_dim[index_x];
          float new_dw_x = ((ETA * delta_val) + (MOMENTUM * oldw_x));
          net->input_units[index_x] += new_dw_x;
          input_weights_prev_one_dim[index_x] = new_dw_x;
        }
      }
    }
  }

  m = 0;
  for (int k = 0; k <= in; k++) {
    for (int j = 0; j <= hid; j++) {
      net->input_weights[k][j] = input_weights_one_dim[m];
      net->input_prev_weights[k][j] = input_weights_prev_one_dim[m];
      m++;
    }
  }

  free(input_weights_prev_one_dim);
  free(partial_sum);
  free(input_weights_one_dim);

  *eo = out_err;
  *eh = hid_err;
  return 0;
}

int setup(int argc, char **argv)
{
  layer_size = -1;
  int cur_arg;
  for (cur_arg = 1; cur_arg < argc; cur_arg++) {
    if (strcmp(argv[cur_arg], "-h") == 0) {
      fprintf(stderr, "usage: backprop <-n num of input elements> [-p platform_id] [-d device_id] [-t device_type]\n");
      exit(0);
    }
    else if (strcmp(argv[cur_arg], "-n") == 0) {
      if (argc >= cur_arg + 1) {
        layer_size = atoi(argv[cur_arg+1]);
        cur_arg++;
      }
    }
    else if (strcmp(argv[cur_arg], "-p") == 0) {
      if (argc >= cur_arg + 1) {
        platform_id_inuse = atoi(argv[cur_arg+1]);
        cur_arg++;
      }
    }
    else if (strcmp(argv[cur_arg], "-d") == 0) {
      if (argc >= cur_arg + 1) {
        device_id_inuse = atoi(argv[cur_arg+1]);
        cur_arg++;
      }
    }
  }

  if (layer_size % 16 != 0){
    fprintf(stderr, "The number of input points must be divided by 16\n");
    exit(0);
  }

  int seed = 7;
  bpnn_initialize(seed);
  backprop_face();
  exit(0);
}

