  }
  for (i = 0; i < m; i++) {
    new_t[i] = alloc_1d_dbl(n);
  }
  return (new_t);
}

void bpnn_randomize_weights(float **w, int m, int n)
{
  int i, j;
  for (i = 0; i <= m; i++) {
    for (j = 0; j <= n; j++) {
      w[i][j] = (float) rand()/RAND_MAX;
    }
  }
}

void bpnn_randomize_row(float *w, int m)
{
  int i;
  for (i = 0; i <= m; i++) {
    w[i] = 0.1;
  }
}

void bpnn_zero_weights(float **w, int m, int n)
{
  int i, j;
  for (i = 0; i <= m; i++) {
    for (j = 0; j <= n; j++) {
      w[i][j] = 0.0;
    }
  }
}

void bpnn_initialize(int seed)
{
  printf("Random number generator seed: %d\n", seed);
  srand(seed);
}

BPNN *bpnn_internal_create(int n_in, int n_hidden, int n_out)
{
  BPNN *newnet;
  newnet = (BPNN *) malloc (sizeof (BPNN));
  if (newnet == NULL) {
    printf("BPNN_CREATE: Couldn't allocate neural network\n");
    return (NULL);
  }
  newnet->input_n = n_in;
  newnet->hidden_n = n_hidden;
  newnet->output_n = n_out;
  newnet->input_units = alloc_1d_dbl(n_in + 1);
  newnet->hidden_units = alloc_1d_dbl(n_hidden + 1);
  newnet->output_units = alloc_1d_dbl(n_out + 1);
  newnet->hidden_delta = alloc_1d_dbl(n_hidden + 1);
  newnet->output_delta = alloc_1d_dbl(n_out + 1);
  newnet->target = alloc_1d_dbl(n_out + 1);
  newnet->input_weights = alloc_2d_dbl(n_in + 1, n_hidden + 1);
  newnet->hidden_weights = alloc_2d_dbl(n_hidden + 1, n_out + 1);
  newnet->input_prev_weights = alloc_2d_dbl(n_in + 1, n_hidden + 1);
  newnet->hidden_prev_weights = alloc_2d_dbl(n_hidden + 1, n_out + 1);
  return (newnet);
}

void bpnn_free(BPNN *net)
{
  int n1, n2, i;
  n1 = net->input_n;
  n2 = net->hidden_n;
  free((char *) net->input_units);
  free((char *) net->hidden_units);
  free((char *) net->output_units);
  free((char *) net->hidden_delta);
  free((char *) net->output_delta);
  free((char *) net->target);
  for (i = 0; i <= n1; i++) {
    free((char *) net->input_weights[i]);
    free((char *) net->input_prev_weights[i]);
  }
  free((char *) net->input_weights);
  free((char *) net->input_prev_weights);
  for (i = 0; i <= n2; i++) {
    free((char *) net->hidden_weights[i]);
    free((char *) net->hidden_prev_weights[i]);
  }
  free((char *) net->hidden_weights);
  free((char *) net->hidden_prev_weights);
  free((char *) net);
}

BPNN *bpnn_create(int n_in, int n_hidden, int n_out)
{
  BPNN *newnet;
  newnet = bpnn_internal_create(n_in, n_hidden, n_out);
#ifdef INITZERO
  bpnn_zero_weights(newnet->input_weights, n_in, n_hidden);
#else
  bpnn_randomize_weights(newnet->input_weights, n_in, n_hidden);
#endif
  bpnn_randomize_weights(newnet->hidden_weights, n_hidden, n_out);
  bpnn_zero_weights(newnet->input_prev_weights, n_in, n_hidden);
  bpnn_zero_weights(newnet->hidden_prev_weights, n_hidden, n_out);
  bpnn_randomize_row(newnet->target, n_out);
  return (newnet);
}

void bpnn_layerforward(float *l1, float *l2, float **conn, int n1, int n2)
{
  float sum;
  int j, k;
  l1[0] = 1.0;
  #pragma omp parallel for shared(conn, n1, n2, l1, l2) private(k, sum) schedule(static)
  for (j = 1; j <= n2; j++) {
    sum = 0.0;
    for (k = 0; k <= n1; k++) {
      sum += conn[k][j] * l1[k];
    }
    l2[j] = squash(sum);
  }
}

void bpnn_output_error(float *delta, float *target, float *output, int nj, float *err)
{
  int j;
  float o, t, errsum;
  errsum = 0.0;
  for (j = 1; j <= nj; j++) {
    o = output[j];
    t = target[j];
    delta[j] = o * (1.0 - o) * (t - o);
    errsum += ABS(delta[j]);
  }
  *err = errsum;
}

void bpnn_hidden_error(float *delta_h, int nh, float *delta_o, int no, float **who, float *hidden, float *err)
{
  int j, k;
  float h, sum, errsum;
  errsum = 0.0;
  for (j = 1; j <= nh; j++) {
    h = hidden[j];
    sum = 0.0;
    for (k = 1; k <= no; k++) {
      sum += delta_o[k] * who[j][k];
    }
    delta_h[j] = h * (1.0 - h) * sum;
    errsum += ABS(delta_h[j]);
  }
  *err = errsum;
}

void bpnn_adjust_weights(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw)
{
  float new_dw;
  int k, j;
  ly[0] = 1.0;
  #pragma omp parallel for shared(oldw, w, delta, ly) private(j, k, new_dw) schedule(static)
  for (j = 1; j <= ndelta; j++) {
    for (k = 0; k <= nly; k++) {
      new_dw = ((ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[k][j]));
      w[k][j] += new_dw;
      oldw[k][j] = new_dw;
    }
  }
}

void bpnn_feedforward(BPNN *net)
{
  int in, hid, out;
  in = net->input_n;
  hid = net->hidden_n;
  out = net->output_n;
  bpnn_layerforward(net->input_units, net->hidden_units, net->input_weights, in, hid);
  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
}

void bpnn_train(BPNN *net, float *eo, float *eh)
{
  int in, hid, out;
  float out_err, hid_err;
  in = net->input_n;
  hid = net->hidden_n;
  out = net->output_n;
  bpnn_layerforward(net->input_units, net->hidden_units, net->input_weights, in, hid);
  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
  bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
  bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, &hid_err);
  *eo = out_err;
  *eh = hid_err;
  bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);
  bpnn_adjust_weights(net->hidden_delta, hid, net->input_units, in, net->input_weights, net->input_prev_weights);
}

void bpnn_save(BPNN *net, char *filename)
{
  int n1, n2, n3, i, j, memcnt;
  float dvalue, **w;
  char *mem;
  FILE *pFile;
  pFile = fopen(filename, "w+");
  n1 = net->input_n; n2 = net->hidden_n; n3 = net->output_n;
  printf("Saving %dx%dx%d network to '%s'\n", n1, n2, n3, filename);
  fwrite((char *) &n1, sizeof(char), sizeof(char), pFile);
  fwrite((char *) &n2, sizeof(char), sizeof(char), pFile);
  fwrite((char *) &n3, sizeof(char), sizeof(char), pFile);
  memcnt = 0;
  w = net->input_weights;
  mem = (char *) malloc ((unsigned) ((n1+1) * (n2+1) * sizeof(float)));
  for (i = 0; i <= n1; i++) {
    for (j = 0; j <= n2; j++) {
      dvalue = w[i][j];
      fastcopy(&mem[memcnt], &dvalue, sizeof(float));
      memcnt += sizeof(float);
    }
  }
  fwrite(mem, (unsigned)(sizeof(float)), (unsigned) ((n1+1) * (n2+1) * sizeof(float)), pFile);
  free(mem);
  memcnt = 0;
  w = net->hidden_weights;
  mem = (char *) malloc ((unsigned) ((n2+1) * (n3+1) * sizeof(float)));
  for (i = 0; i <= n2; i++) {
    for (j = 0; j <= n3; j++) {
      dvalue = w[i][j];
      fastcopy(&mem[memcnt], &dvalue, sizeof(float));
      memcnt += sizeof(float);
    }
  }
  fwrite(mem, sizeof(float), (unsigned) ((n2+1) * (n3+1) * sizeof(float)), pFile);
  free(mem);
  fclose(pFile);
  return;
}

BPNN *bpnn_read(char *filename)
{
  char *mem;
  BPNN *new_t;
  int fd, n1, n2, n3, i, j, memcnt;
  if ((fd = open(filename, 0, 0644)) == -1) {
    return (NULL);
  }
  printf("Reading '%s'\n", filename);
  read(fd, (char *) &n1, sizeof(int));
  read(fd, (char *) &n2, sizeof(int));
  read(fd, (char *) &n3, sizeof(int));
  new_t = bpnn_internal_create(n1, n2, n3);
  printf("'%s' contains a %dx%dx%d network\n", filename, n1, n2, n3);
  printf("Reading input weights...");
  memcnt = 0;
  mem = (char *) malloc ((unsigned) ((n1+1) * (n2+1) * sizeof(float)));
  read(fd, mem, (n1+1) * (n2+1) * sizeof(float));
  for (i = 0; i <= n1; i++) {
    for (j = 0; j <= n2; j++) {
      fastcopy(&(new_t->input_weights[i][j]), &mem[memcnt], sizeof(float));
      memcnt += sizeof(float);
    }
  }
  free(mem);
  printf("Done\nReading hidden weights...");
  memcnt = 0;
  mem = (char *) malloc ((unsigned) ((n2+1) * (n3+1) * sizeof(float)));
  read(fd, mem, (n2+1) * (n3+1) * sizeof(float));
  for (i = 0; i <= n2; i++) {
    for (j = 0; j <= n3; j++) {
      fastcopy(&(new_t->hidden_weights[i][j]), &mem[memcnt], sizeof(float));
      memcnt += sizeof(float);
    }
  }
  free(mem);
  close(fd);
  printf("Done\n");
  bpnn_zero_weights(new_t->input_prev_weights, n1, n2);
  bpnn_zero_weights(new_t->hidden_prev_weights, n2, n3);
  return (new_t);
}

void bpnn_layerforward_ocl(float *input_cuda, float *output_hidden_cuda, float *input_hidden_cuda, float *hidden_partial_sum, int in, int hid)
{
  int by, tx, ty;
  int index, index_in;
  float input_node[HEIGHT];
  float weight_matrix[HEIGHT * WIDTH];

  int num_blocks = in / BLOCK_SIZE;

  #pragma omp parallel for private(by, tx, ty, index, index_in) shared(input_cuda, output_hidden_cuda, input_hidden_cuda, hidden_partial_sum, input_node, weight_matrix)
  for (by = 0; by < num_blocks; by++) {
    for (ty = 0; ty < HEIGHT; ty++) {
      for (tx = 0; tx < WIDTH; tx++) {
        index = (hid + 1) * HEIGHT * by + (hid + 1) * ty + tx + 1 + (hid + 1);
        index_in = HEIGHT * by + ty + 1;

        if (tx == 0) {
          input_node[ty] = input_cuda[index_in];
        }

        weight_matrix[ty * WIDTH + tx] = input_hidden_cuda[index];

        weight_matrix[ty * WIDTH + tx] = weight_matrix[ty * WIDTH + tx] * input_node[ty];

        for (int i = 1; i <= HEIGHT; i = i * 2) {
          int power_two = i;
          if (ty % power_two == 0 && (ty + power_two/2) < HEIGHT) {
            weight_matrix[ty * WIDTH + tx] = weight_matrix[ty * WIDTH + tx] + weight_matrix[(ty + power_two/2) * WIDTH + tx];
          }
        }

        input_hidden_cuda[index] = weight_matrix[ty * WIDTH + tx];

        if (tx == 0) {
          hidden_partial_sum[by * hid + ty] = weight_matrix[0 * WIDTH + ty];
        }
      }
    }
  }
}

void bpnn_adjust_weights_ocl(float *delta, int hid, float *ly, int in, float *w, float *oldw)
{
  int by, tx, ty;
  int index, index_y, index_x;
  int num_blocks = in / BLOCK_SIZE;

  #pragma omp parallel for private(by, tx, ty, index, index_y, index_x) shared(delta, hid, ly, in, w, oldw)
  for (by = 0; by < num_blocks; by++) {
    for (ty = 0; ty < HEIGHT; ty++) {
      for (tx = 0; tx < WIDTH; tx++) {
        index = (hid + 1) * HEIGHT * by + (hid + 1) * ty + tx + 1 + (hid + 1);
        index_y = HEIGHT * by + ty + 1;
        index_x = tx + 1;

        if (index <= (in + 1) * (hid + 1) && index_x <= hid + 1 && index_y <= in + 1) {
          float update = ((ETA * delta[index_x] * ly[index_y]) + (MOMENTUM * oldw[index]));
          w[index] += update;
          oldw[index] = update;
        }

        if (ty == 0 && by == 0 && index_x <= hid + 1) {
          float update = ((ETA * delta[index_x]) + (MOMENTUM * oldw[index_x]));
          w[index_x] += update;
          oldw[index_x] = update;
        }
      }
    }
  }
}

int bpnn_train_kernel(BPNN *net, float *eo, float *eh)
{
  int in, hid, out;
  float out_err, hid_err;
  float *input_weights_one_dim;
  float *input_weights_prev_one_dim;
  float *partial_sum;
  float sum;
  int num_blocks;
  int m, k, j;

  in = net->input_n;
  hid = net->hidden_n;
  out = net->output_n;

  num_blocks = in / BLOCK_SIZE;

  input_weights_one_dim = (float *) malloc((in + 1) * (hid + 1) * sizeof(float));
  input_weights_prev_one_dim = (float *) malloc((in + 1) * (hid + 1) * sizeof(float));
  partial_sum = (float *) malloc(num_blocks * WIDTH * sizeof(float));

  m = 0;
  for (k = 0; k <= in; k++) {
    for (j = 0; j <= hid; j++) {
      input_weights_one_dim[m] = net->input_weights[k][j];
      input_weights_prev_one_dim[m] = net->input_prev_weights[k][j];
      m++;
    }
  }

  printf("Performing CPU computation\n");

  bpnn_layerforward_ocl(net->input_units, net->hidden_units, input_weights_one_dim, partial_sum, in, hid);

  for (j = 1; j <= hid; j++) {
    sum = 0.0;
    for (k = 0; k < num_blocks; k++) {
      sum += partial_sum[k * hid + j - 1];
    }
    sum += net->input_weights[0][j];
    net->hidden_units[j] = squash(sum);
  }

  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
  bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
  bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, &hid_err);
  bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);

  bpnn_adjust_weights_ocl(net->hidden_delta, hid, net->input_units, in, input_weights_one_dim, input_weights_prev_one_dim);

  m = 0;
  for (k = 0; k <= in; k++) {
    for (j = 0; j <= hid; j++) {
      net->input_weights[k][j] = input_weights_one_dim[m];
      net->input_prev_weights[k][j] = input_weights_prev_one_dim[m];
      m++;
    }
  }

  free(input_weights_prev_one_dim);
  free(partial_sum);
  free(input_weights_one_dim);

  *eo = out_err;
  *eh = hid_err;

  return 0;
}

int layer_size = 0;
int platform_id_inuse = 0;
int device_id_inuse = 0;

void load(BPNN *net)
{
  float *units;
  int nr, nc, imgsize, i, k;
  nr = layer_size;
  nc = 16;
  imgsize = nr * nc;
  units = net->input_units;
  k = 1;
  for (i = 0; i < nr; i++) {
    units[k] = (float) rand()/RAND_MAX;
    k++;
  }
}

void backprop_face()
{
  BPNN *net;
  float out_err, hid_err;
  net = bpnn_create(layer_size, 16, 1);
  printf("Input layer size : %d\n", layer_size);
  load(net);
  printf("Starting training kernel\n");
  bpnn_train_kernel(net, &out_err, &hid_err);
  bpnn_free(net);
  printf("\nFinish the training for one iteration\n");
}

int setup(int argc, char **argv)
{
  int cur_arg;
  layer_size = -1;
  for (cur_arg = 1; cur_arg < argc; cur_arg++) {
    if (strcmp(argv[cur_arg], "-h") == 0) {
      fprintf(stderr, "usage: backprop <-n num of input elements> [-p platform_id] [-d device_id] [-t device_type]\n");
      exit(0);
    }
    else if (strcmp(argv[cur_arg], "-n") == 0) {
      if (argc >= cur_arg + 1) {
        layer_size = atoi(argv[cur_arg+1]);
        cur_arg++;
      }
    }
    else if (strcmp(argv[cur_arg], "-p") == 0) {
      if (argc >= cur_arg + 1) {
        platform_id_inuse = atoi(argv[cur_arg+1]);
        cur_arg++;
      }
    }
    else if (strcmp(argv[cur_arg], "-d") == 0) {
      if (argc >= cur_arg + 1) {
        device_id_inuse = atoi(argv[cur_arg+1]);
        cur_arg++;
      }
    }
  }
  if (layer_size % 16 != 0) {
    fprintf(stderr, "The number of input points must be divided by 16\n");
    exit(0);
  }
  int seed = 7;
  bpnn_initialize(seed);
  backprop_face();
  exit(0);
}

int main(int argc, char** argv)
{
  setup(argc, argv);
  return 0;
}

