			ff_flux_contribution_momentum_z_host = new float[3];
			ff_flux_contribution_density_energy_host = new float[3];

			for(int i=0; i<NVAR; i++) ff_variable_host[i] = h_ff_variable[i];

			((FLOAT3*)ff_flux_contribution_momentum_x_host)[0] = h_ff_flux_contribution_momentum_x;
			((FLOAT3*)ff_flux_contribution_momentum_y_host)[0] = h_ff_flux_contribution_momentum_y;
			((FLOAT3*)ff_flux_contribution_momentum_z_host)[0] = h_ff_flux_contribution_momentum_z;
			((FLOAT3*)ff_flux_contribution_density_energy_host)[0] = h_ff_flux_contribution_density_energy;
		}

		int nel;
		int nelr;

		{
			std::ifstream file(data_file_name);
			if(!file){
				throw(std::string("can not find/open file!"));
			}
			file >> nel;
			nelr = block_length*((nel / block_length )+ std::min(1, nel % block_length));
			std::cout<<"--cambine: nel="<<nel<<", nelr="<<nelr<<std::endl;

			areas_host = new float[nelr];
			elements_surrounding_elements_host = new int[nelr*NNB];
			normals_host = new float[nelr*NDIM*NNB];

			for(int i = 0; i < nel; i++)
			{
				file >> areas_host[i];
				for(int j = 0; j < NNB; j++)
				{
					file >> elements_surrounding_elements_host[i + j*nelr];
					if(elements_surrounding_elements_host[i+j*nelr] < 0) elements_surrounding_elements_host[i+j*nelr] = -1;
					elements_surrounding_elements_host[i + j*nelr]--; 

					for(int k = 0; k < NDIM; k++)
					{
						file >> normals_host[i + (j + k*NNB)*nelr];
						normals_host[i + (j + k*NNB)*nelr] = -normals_host[i + (j + k*NNB)*nelr];
					}
				}
			}

			int last = nel-1;
			for(int i = nel; i < nelr; i++)
			{
				areas_host[i] = areas_host[last];
				for(int j = 0; j < NNB; j++)
				{
					elements_surrounding_elements_host[i + j*nelr] = elements_surrounding_elements_host[last + j*nelr];	
					for(int k = 0; k < NDIM; k) normals_host[last + (j + k*NNB)*nelr] = normals_host[last + (j + k*NNB)*nelr];
				}
			}
		}

		variables_host = new float[nelr*NVAR];				
		int tp = 0;
		initialize_variables(variables_host, ff_variable_host, nelr);			

		old_variables_host = new float[nelr*NVAR];   
		fluxes_host = new float[nelr*NVAR];
		step_factors_host = new float[nelr]; 

		initialize_variables(old_variables_host, ff_variable_host, nelr);	
		initialize_variables(fluxes_host, ff_variable_host, nelr);		
		memset_kernel((char*)step_factors_host, 0, sizeof(float)*nelr);

		std::cout << "Starting..." << std::endl;

		for(int i = 0; i < iterations; i++){
			#pragma omp parallel for
			for(int k=0; k<nelr*NVAR; k++) old_variables_host[k] = variables_host[k];

			compute_step_factor(variables_host, areas_host, step_factors_host, nelr);
			for(int j = 0; j < RK; j++){
				FLOAT3* ff_fc_de = (FLOAT3*)ff_flux_contribution_density_energy_host;
				FLOAT3* ff_fc_mx = (FLOAT3*)ff_flux_contribution_momentum_x_host;
				FLOAT3* ff_fc_my = (FLOAT3*)ff_flux_contribution_momentum_y_host;
				FLOAT3* ff_fc mz = (FLOAT3*)ff_flux_contribution_momentum_z_host;

				compute_flux(elements_surrounding_elements_host, normals_host, variables_host, ff_variable_host, fluxes_host, ff_fc_de, ff_fc_mx, ff_fc_my, ff_fc mz, nelr);

				time_step(j, nelr, old_variables_host, variables_host, step_factors_host, fluxes_host);
			}
		}

		std::cout << "Saving solution..." << std::endl;
		dump(variables_host, nel, nelr);
		std::cout << "Saved solution..." << std::endl;
		std::cout << "Cleaning up..." << std::endl;

		delete[] ff_variable_host;
		delete[] ff_flux_contribution_momentum_x_host;
		delete[] ff_flux_contribution_momentum_y_host;
		delete[] ff_flux_contribution_momentum_z_host;
		delete[] ff_flux_contribution_density_energy_host;
		delete[] areas_host;
		delete[] elements_surrounding_elements_host;
		delete[] normals_host;
		delete[] variables_host;
		delete[] old_variables_host;
		delete[] fluxes_host;
		delete[] step_factors_host;

		std::cout << "Done..." << std::endl;
	}
	catch(std::string msg){
		std::cout<<"--cambine:( an exception catched in main body ->"<<msg<<std::endl;		
	}
	catch(...){
		std::cout<<"--cambine:( unknow exceptions in main body..."<<std::endl;		
	}

	return 0;
}

