				for(i=0; i<d_common.in_sqr_rows; i++){
					checksum[26] = checksum[26]+in_sqr_partial_sum[i];
				}
			}


#endif



			if(tx == 0){

				in_final_sum[0] = 0;
				for(i = 0; i<d_common.in_cols; i++){

					in_final_sum[0] = in_final_sum[0] + in_partial_sum[i];
				}

			}else if(tx == 1){

				in_sqr_final_sum[0] = 0;
				for(i = 0; i<d_common.in_sqr_cols; i++){

					in_sqr_final_sum[0] = in_sqr_final_sum[0] + in_sqr_partial_sum[i];
				}

			}





#ifdef TEST_CHECKSUM
			if(bx==0 && tx==0){
				checksum[27] = checksum[27]+in_final_sum[0]+in_sqr_final_sum[0];
			}


#endif



			if(tx == 0){


				mean = in_final_sum[0] / d_common.in_elem;													
				mean_sqr = mean * mean;

				variance  = (in_sqr_final_sum[0] / d_common.in_elem) - mean_sqr;							
				deviation = sqrt(variance);																


				denomT[0] = sqrt((float)(d_common.in_elem-1))*deviation;

			}





#ifdef TEST_CHECKSUM
			if(bx==0 && tx==0){
				checksum[28] = checksum[28]+denomT[i];
			}


#endif




			ei_new = tx;
			while(ei_new < d_common.in2_sub2_elem){


				d_unique_d_in2_sqr_sub2[ei_new] = d_unique_d_in2_sqr_sub2[ei_new] * denomT[0];


				ei_new = ei_new + NUMBER_THREADS;

			}





#ifdef TEST_CHECKSUM
			if(bx==0 && tx==0){
				for(i=0; i<d_common.in2_sub2_elem; i++){
					checksum[29] = checksum[29]+d_unique_d_in2_sqr_sub2[i];
				}
			}


#endif




			ei_new = tx;
			while(ei_new < d_common.conv_elem){


				d_unique_d_conv[ei_new] = d_unique_d_conv[ei_new] - d_unique_d_in2_sub2[ei_new] * in_final_sum[0] / d_common.in_elem;


				ei_new = ei_new + NUMBER_THREADS;

			}





#ifdef TEST_CHECKSUM
			if(bx==0 && tx==0){
				for(i=0; i<d_common.conv_elem; i++){
					checksum[30] = checksum[30]+d_unique_d_conv[i];
				}
			}


#endif




			ei_new = tx;
			while(ei_new < d_common.in2_sub2_elem){

				d_unique_d_in2_sqr_sub2[ei_new] = d_unique_d_conv[ei_new] / d_unique_d_in2_sqr_sub2[ei_new];


				ei_new = ei_new + NUMBER_THREADS;

			}







#ifdef TEST_CHECKSUM
			if(bx==0 && tx==0){
				for(i=0; i<d_common.in2_sub2_elem; i++){
					checksum[31] = checksum[31]+d_unique_d_in2_sqr_sub2[i];
				}
			}


#endif




			cent = d_common.sSize + d_common.tSize + 1;
			if(d_frame_no == 0){
				tMask_row = cent + d_unique_d_Row[d_unique_point_no] - d_unique_d_Row[d_unique_point_no] - 1;
				tMask_col = cent + d_unique_d_Col[d_unique_point_no] - d_unique_d_Col[d_unique_point_no] - 1;
			}
			else{
				pointer = d_unique_point_no*d_common.no_frames+d_frame_no-1;
				tMask_row = cent + d_unique_d_tRowLoc[pointer] - d_unique_d_Row[d_unique_point_no] - 1;
				tMask_col = cent + d_unique_d_tColLoc[pointer] - d_unique_d_Col[d_unique_point_no] - 1;
			}


			ei_new = tx;
			while(ei_new < d_common.tMask_elem){

				location = tMask_col*d_common.tMask_rows + tMask_row;

				if(ei_new==location){
					d_unique_d_tMask[ei_new] = 1;
				}
				else{
					d_unique_d_tMask[ei_new] = 0;
				}


				ei_new = ei_new + NUMBER_THREADS;

			}





#ifdef TEST_CHECKSUM
			if(bx==0 && tx==0){
				for(i=0; i<d_common.tMask_elem; i++){
					checksum[32] = checksum[32]+d_unique_d_tMask[i];
				}
			}


#endif







			ei_new = tx;
			while(ei_new < d_common.mask_conv_elem){


				ic = (ei_new+1) % d_common.mask_conv_rows;												
				jc = (ei_new+1) / d_common.mask_conv_rows + 1;											
				if((ei_new+1) % d_common.mask_conv_rows == 0){
					ic = d_common.mask_conv_rows;
					jc = jc-1;
				}


				j = jc + d_common.mask_conv_joffset;
				jp1 = j + 1;
				if(d_common.mask_cols < jp1){
					ja1 = jp1 - d_common.mask_cols;
				}
				else{
					ja1 = 1;
				}
				if(d_common.tMask_cols < j){
					ja2 = d_common.tMask_cols;
				}
				else{
					ja2 = j;
				}

				i = ic + d_common.mask_conv_ioffset;
				ip1 = i + 1;

				if(d_common.mask_rows < ip1){
					ia1 = ip1 - d_common.mask_rows;
				}
				else{
					ia1 = 1;
				}
				if(d_common.tMask_rows < i){
					ia2 = d_common.tMask_rows;
				}
				else{
					ia2 = i;
				}

				s = 0;

				for(ja=ja1; ja<=ja2; ja++){
					jb = jp1 - ja;
					for(ia=ia1; ia<=ia2; ia++){
						ib = ip1 - ia;
						s = s + d_unique_d_tMask[d_common.tMask_rows*(ja-1)+ia-1] * 1;
					}
				}


				d_unique_d_mask_conv[ei_new] = d_unique_d_in2_sqr_sub2[ei_new] * s;


				ei_new = ei_new + NUMBER_THREADS;

			}





#ifdef TEST_CHECKSUM
			if(bx==0 && tx==0){
				for(i=0; i<d_common.mask_conv_elem; i++){
					checksum[33] = checksum[33]+d_unique_d_mask_conv[i];
				}
			}


#endif






			ei_new = tx;
			while(ei_new < d_common.mask_conv_rows){

				for(i=0; i<d_common.mask_conv_cols; i++){
					largest_coordinate_current = ei_new*d_common.mask_conv_rows+i;
					largest_value_current = fabs(d_unique_d_mask_conv[largest_coordinate_current]);
					if(largest_value_current > largest_value){
						largest_coordinate = largest_coordinate_current;
						largest_value = largest_value_current;
					}
				}
				par_max_coo[ei_new] = largest_coordinate;
				par_max_val[ei_new] = largest_value;


				ei_new = ei_new + NUMBER_THREADS;

			}





#ifdef TEST_CHECKSUM
			if(bx==0 && tx==0){
				for(i=0; i<d_common.mask_conv_rows; i++){
					checksum[34] = checksum[34]+par_max_coo[i]+par_max_val[i];
				}
			}


#endif



			if(tx == 0){

				for(i = 0; i < d_common.mask_conv_rows; i++){
					if(par_max_val[i] > fin_max_val){
						fin_max_val = par_max_val[i];
						fin_max_coo = par_max_coo[i];
					}
				}


				largest_row = (fin_max_coo+1) % d_common.mask_conv_rows - 1;											
				largest_col = (fin_max_coo+1) / d_common.mask_conv_rows;												
				if((fin_max_coo+1) % d_common.mask_conv_rows == 0){
					largest_row = d_common.mask_conv_rows - 1;
					largest_col = largest_col - 1;
				}


				largest_row = largest_row + 1;																	
				largest_col = largest_col + 1;																	
				offset_row = largest_row - d_common.in_rows - (d_common.sSize - d_common.tSize);
				offset_col = largest_col - d_common.in_cols - (d_common.sSize - d_common.tSize);
				pointer = d_unique_point_no*d_common.no_frames+d_frame_no;
				d_unique_d_tRowLoc[pointer] = d_unique_d_Row[d_unique_point_no] + offset_row;
				d_unique_d_tColLoc[pointer] = d_unique_d_Col[d_unique_point_no] + offset_col;

			}





#ifdef TEST_CHECKSUM
			if(bx==0 && tx==0){
				checksum[35] = checksum[35]+d_unique_d_tRowLoc[pointer]+d_unique_d_tColLoc[pointer];
			}


#endif






		}




		if(d_frame_no != 0 && (d_frame_no)%10 == 0){



#ifdef INIT

			if(tx==0){


				for(i=0; i<d_common.in_elem; i++){
					d_in[i] = 0;
				}

			}
#endif







			loc_pointer = d_unique_point_no*d_common.no_frames+d_frame_no;

			d_unique_d_Row[d_unique_point_no] = d_unique_d_tRowLoc[loc_pointer];
			d_unique_d_Col[d_unique_point_no] = d_unique_d_tColLoc[loc_pointer];


			ei_new = tx;
			while(ei_new < d_common.in_elem){


				row = (ei_new+1) % d_common.in_rows - 1;												
				col = (ei_new+1) / d_common.in_rows + 1 - 1;											
				if((ei_new+1) % d_common.in_rows == 0){
					row = d_common.in_rows - 1;
					col = col-1;
				}


				ori_row = d_unique_d_Row[d_unique_point_no] - 25 + row - 1;
				ori_col = d_unique_d_Col[d_unique_point_no] - 25 + col - 1;
				ori_pointer = ori_col*d_common.frame_rows+ori_row;


				d_in[ei_new] = d_common.alpha*d_in[ei_new] + (1-d_common.alpha)*d_common_change_d_frame[ori_pointer];


				ei_new = ei_new + NUMBER_THREADS;

			}





#ifdef TEST_CHECKSUM
			if(bx==0 && tx==0){
				for(i=0; i<d_common.in_elem; i++){
					checksum[36] = checksum[36]+d_in[i];
				}
			}


#endif






		}




	}
}

#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <omp.h>

#include "./main.h"
#include "./util/avi/avilib.h"
#include "./util/avi/avimod.h"
#include "./util/file/file.h"
#include "./kernel/kernel_gpu_opencl_wrapper.h"

int platform_id_inuse = 0; 
int device_id_inuse = 0; 

void kernel_gpu_opencl_wrapper(params_common common,
							int* endoRow,
							int* endoCol,
							int* tEndoRowLoc,
							int* tEndoColLoc,
							int* epiRow,
							int* epiCol,
							int* tEpiRowLoc,
							int* tEpiColLoc,
							avi_t* frames)
{
	int i, j, frame_no;
	fp* frame;
	fp* checksum;

	printf("WG size of kernel = %d \n", NUMBER_THREADS);

	printf("frame progress: ");
	fflush(NULL);

	for(frame_no=0; frame_no<common.frames_processed; frame_no++){

		frame = get_frame(frames, frame_no, 0, 0, 1);

		#pragma omp parallel num_threads(NUMBER_THREADS)
		{
			int bx = omp_get_thread_num();
			int tx = bx; 
			int ei_new;
			int rot_row, rot_col, in2_rowlow, in2_collow, ic, jc, jp1, ja1, ja2, ip1, ia1, ia2, ja, jb, ia, ib;
			fp s, sum, temp, temp2, mean, mean_sqr, variance, deviation, denomT;
			int row, col, ori_row, ori_col, position, pos_ori, location, cent, tMask_row, tMask_col;
			fp largest_value_current = 0, largest_value = 0, fin_max_val = 0;
			int largest_coordinate_current = 0, largest_coordinate = 0, fin_max_coo = 0;
			int largest_row, largest_col, offset_row, offset_col, pointer, ori_pointer, loc_pointer;

			int d_unique_point_no;
			int* d_unique_d_Row;
			int* d_unique_d_Col;
			int* d_unique_d_tRowLoc;
			int* d_unique_d_tColLoc;
			fp* d_in;

			fp* d_unique_d_in2;
			fp* d_unique_d_conv;
			fp* d_unique_d_in2_pad_cumv;
			fp* d_unique_d_in2_pad_cumv_sel;
			fp* d_unique_d_in2_sub_cumh;
			fp* d_unique_d_in2_sub_cumh_sel;
			fp* d_unique_d_in2_sub2;
			fp* d_unique_d_in2_sqr;
			fp* d_unique_d_in2_sqr_sub2;
			fp* d_unique_d_in_sqr;
			fp* d_unique_d_tMask;
			fp* d_unique_d_mask_conv;

			fp* d_in_mod_temp;
			fp* in_partial_sum;
			fp* in_sqr_partial_sum;
			fp* par_max_val;
			int* par_max_coo;
			fp* in_final_sum;
			fp* in_sqr_final_sum;
			fp* denomT_ptr;

			fp* d_common_change_d_frame = frame;

			if(bx < common.endoPoints){
				d_unique_point_no = bx;
				d_unique_d_Row = endoRow;
				d_unique_d_Col = endoCol;
				d_unique_d_tRowLoc = tEndoRowLoc;
				d_unique_d_tColLoc = tEndoColLoc;
				d_in = &((fp*)malloc(common.in_mem * common.endoPoints))[d_unique_point_no * common.in_elem];
				if(bx == 0) {
					for(int k=0; k<common.endoPoints*common.in_elem; k++) ((fp*)malloc(common.in_mem * common.endoPoints))[k] = 0; 
				}
			}
			else{
				d_unique_point_no = bx - common.endoPoints;
				d_unique_d_Row = epiRow;
				d_unique_d_Col = epiCol;
				d_unique_d_tRowLoc = tEpiRowLoc;
				d_unique_d_tColLoc = tEpiColLoc;
				d_in = &((fp*)malloc(common.in_mem * common.epiPoints))[d_unique_point_no * common.in_elem];
				if(bx == common.endoPoints) {
					for(int k=0; k<common.epiPoints*common.in_elem; k++) ((fp*)malloc(common.in_mem * common.epiPoints))[k] = 0;
				}
			}

			d_unique_d_in2 = (fp*)malloc(sizeof(fp) * common.in2_elem);
			d_unique_d_conv = (fp*)malloc(sizeof(fp) * common.conv_elem);
			d_unique_d_in2_pad_cumv = (fp*)malloc(sizeof(fp) * common.in2_pad_cumv_elem);
			d_unique_d_in2_pad_cumv_sel = (fp*)malloc(sizeof(fp) * common.in2_pad_cumv_sel_elem);
			d_unique_d_in2_sub_cumh = (fp*)malloc(sizeof(fp) * common.in2_sub_cumh_elem);
			d_unique_d_in2_sub_cumh_sel = (fp*)malloc(sizeof(fp) * common.in2_sub_cumh_sel_elem);
			d_unique_d_in2_sub2 = (fp*)malloc(sizeof(fp) * common.in2_sub2_elem);
			d_unique_d_in2_sqr = (fp*)malloc(sizeof(fp) * common.in2_sqr_elem);
			d_unique_d_in2_sqr_sub2 = (fp*)malloc(sizeof(fp) * common.in2_sqr_sub2_elem);
			d_unique_d_in_sqr = (fp*)malloc(sizeof(fp) * common.in_sqr_elem);
			d_unique_d_tMask = (fp*)malloc(sizeof(fp) * common.tMask_elem);
			d_unique_d_mask_conv = (fp*)malloc(sizeof(fp) * common.mask_conv_elem);

			d_in_mod_temp = (fp*)malloc(sizeof(fp) * common.in_elem);
			in_partial_sum = (fp*)malloc(sizeof(fp) * common.in_cols);
			in_sqr_partial_sum = (fp*)malloc(sizeof(fp) * common.in_sqr_rows);
			par_max_val = (fp*)malloc(sizeof(fp) * common.mask_conv_rows);
			par_max_coo = (int*)malloc(sizeof(int) * common.mask_conv_rows);
			in_final_sum = (fp*)malloc(sizeof(fp));
			in_sqr_final_sum = (fp*)malloc(sizeof(fp));
			denomT_ptr = (fp*)malloc(sizeof(fp));

			for(i=0; i<common.in2_elem; i++) d_unique_d_in2[i] = 0;
			for(i=0; i<common.conv_elem; i++) d_unique_d_conv[i] = 0;
			for(i=0; i<common.in2_pad_cumv_elem; i++) d_unique_d_in2_pad_cumv[i] = 0;
			for(i=0; i<common.in2_pad_cumv_sel_elem; i++) d_unique_d_in2_pad_cumv_sel[i] = 0;
			for(i=0; i<common.in2_sub_cumh_elem; i++) d_unique_d_in2_sub_cumh[i] = 0;
			for(i=0; i<common.in2_sub_cumh_sel_elem; i++) d_unique_d_in2_sub_cumh_sel[i] = 0;
			for(i=0; i<common.in2_sub2_elem; i++) d_unique_d_in2_sub2[i] = 0;
			for(i=0; i<common.in2_sqr_elem; i++) d_unique_d_in2_sqr[i] = 0;
			for(i=0; i<common.in2_sqr_sub2_elem; i++) d_unique_d_in2_sqr_sub2[i] = 0;
			for(i=0; i<common.in_sqr_elem; i++) d_unique_d_in_sqr[i] = 0;
			for(i=0; i<common.tMask_elem; i++) d_unique_d_tMask[i] = 0;
			for(i=0; i<common.mask_conv_elem; i++) d_unique_d_mask_conv[i] = 0;
			for(i=0; i<common.in_elem; i++) d_in_mod_temp[i] = 0;
			for(i=0; i<common.in_cols; i++) in_partial_sum[i] = 0;
			for(i=0; i<common.in_sqr_rows; i++) in_sqr_partial_sum[i] = 0;
			for(i=0; i<common.mask_conv_rows; i++) par_max_val[i] = 0;
			for(i=0; i<common.mask_conv_rows; i++) par_max_coo[i] = 0;
			in_final_sum[0] = 0;
			in_sqr_final_sum[0] = 0;
			denomT_ptr[0] = 0;

			if(frame_no == 0){
				if(tx==0){
					for(i=0; i<common.no_frames; i++){
						d_unique_d_tRowLoc[d_unique_point_no*common.no_frames+i] = 0;
						d_unique_d_tColLoc[d_unique_point_no*common.no_frames+i] = 0;
					}
					for(i=0; i<common.in_elem; i++){
						d_in[i] = 0;
					}
				}

				pointer = d_unique_point_no*common.no_frames+frame_no;
				d_unique_d_tRowLoc[pointer] = d_unique_d_Row[d_unique_point_no];
				d_unique_d_tColLoc[pointer] = d_unique_d_Col[d_unique_point_no];

				ei_new = tx;
				while(ei_new < common.in_elem){
					row = (ei_new+1) % common.in_rows - 1;
					col = (ei_new+1) / common.in_rows + 1 - 1;
					if((ei_new+1) % common.in_rows == 0){
						row = common.in_rows - 1;
						col = col-1;
					}
					ori_row = d_unique_d_Row[d_unique_point_no] - 25 + row - 1;
					ori_col = d_unique_d_Col[d_unique_point_no] - 25 + col - 1;
					ori_pointer = ori_col*common.frame_rows+ori_row;
					d_in[col*common.in_rows+row] = d_common_change_d_frame[ori_pointer];
					ei_new = ei_new + NUMBER_THREADS;
				}
			}

			if(frame_no != 0){
				in2_rowlow = d_unique_d_Row[d_unique_point_no] - common.sSize;
				in2_collow = d_unique_d_Col[d_unique_point_no] - common.sSize;

				ei_new = tx;
				while(ei_new < common.in2_elem){
					row = (ei_new+1) % common.in2_rows - 1;
					col = (ei_new+1) / common.in2_rows + 1 - 1;
					if((ei_new+1) % common.in2_rows == 0){
						row = common.in2_rows - 1;
						col = col-1;
					}
					ori_row = row + in2_rowlow - 1;
					ori_col = col + in2_collow - 1;
					d_unique_d_in2[ei_new] = d_common_change_d_frame[ori_col*common.frame_rows+ori_row];
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in_elem){
					row = (ei_new+1) % common.in_rows - 1;
					col = (ei_new+1) / common.in_rows + 1 - 1;
					if((ei_new+1) % common.in_rows == 0){
						row = common.in_rows - 1;
						col = col-1;
					}
					rot_row = (common.in_rows-1) - row;
					rot_col = (common.in_rows-1) - col;
					d_in_mod_temp[ei_new] = d_in[rot_col*common.in_rows+rot_row];
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.conv_elem){
					ic = (ei_new+1) % common.conv_rows;
					jc = (ei_new+1) / common.conv_rows + 1;
					if((ei_new+1) % common.conv_rows == 0){
						ic = common.conv_rows;
						jc = jc-1;
					}
					j = jc + common.joffset;
					jp1 = j + 1;
					if(common.in2_cols < jp1){
						ja1 = jp1 - common.in2_cols;
					}
					else{
						ja1 = 1;
					}
					if(common.in_cols < j){
						ja2 = common.in_cols;
					}
					else{
						ja2 = j;
					}
					i = ic + common.ioffset;
					ip1 = i + 1;
					if(common.in2_rows < ip1){
						ia1 = ip1 - common.in2_rows;
					}
					else{
						ia1 = 1;
					}
					if(common.in_rows < i){
						ia2 = common.in_rows;
					}
					else{
						ia2 = i;
					}
					s = 0;
					for(ja=ja1; ja<=ja2; ja++){
						jb = jp1 - ja;
						for(ia=ia1; ia<=ia2; ia++){
							ib = ip1 - ia;
							s = s + d_in_mod_temp[common.in_rows*(ja-1)+ia-1] * d_unique_d_in2[common.in2_rows*(jb-1)+ib-1];
						}
					}
					d_unique_d_conv[ei_new] = s;
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in2_pad_cumv_elem){
					row = (ei_new+1) % common.in2_pad_cumv_rows - 1;
					col = (ei_new+1) / common.in2_pad_cumv_rows + 1 - 1;
					if((ei_new+1) % common.in2_pad_cumv_rows == 0){
						row = common.in2_pad_cumv_rows - 1;
						col = col-1;
					}
					if(row > (common.in2_pad_add_rows-1) && row < (common.in2_pad_add_rows+common.in2_rows) && 
					   col > (common.in2_pad_add_cols-1) && col < (common.in2_pad_add_cols+common.in2_cols)){
						ori_row = row - common.in2_pad_add_rows;
						ori_col = col - common.in2_pad_add_cols;
						d_unique_d_in2_pad_cumv[ei_new] = d_unique_d_in2[ori_col*common.in2_rows+ori_row];
					}
					else{
						d_unique_d_in2_pad_cumv[ei_new] = 0;
					}
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in2_pad_cumv_cols){
					pos_ori = ei_new*common.in2_pad_cumv_rows;
					sum = 0;
					for(position = pos_ori; position < pos_ori+common.in2_pad_cumv_rows; position = position + 1){
						d_unique_d_in2_pad_cumv[position] = d_unique_d_in2_pad_cumv[position] + sum;
						sum = d_unique_d_in2_pad_cumv[position];
					}
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in2_pad_cumv_sel_elem){
					row = (ei_new+1) % common.in2_pad_cumv_sel_rows - 1;
					col = (ei_new+1) / common.in2_pad_cumv_sel_rows + 1 - 1;
					if((ei_new+1) % common.in2_pad_cumv_sel_rows == 0){
						row = common.in2_pad_cumv_sel_rows - 1;
						col = col-1;
					}
					ori_row = row + common.in2_pad_cumv_sel_rowlow - 1;
					ori_col = col + common.in2_pad_cumv_sel_collow - 1;
					d_unique_d_in2_pad_cumv_sel[ei_new] = d_unique_d_in2_pad_cumv[ori_col*common.in2_pad_cumv_rows+ori_row];
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in2_sub_cumh_elem){
					row = (ei_new+1) % common.in2_sub_cumh_rows - 1;
					col = (ei_new+1) / common.in2_sub_cumh_rows + 1 - 1;
					if((ei_new+1) % common.in2_sub_cumh_rows == 0){
						row = common.in2_sub_cumh_rows - 1;
						col = col-1;
					}
					ori_row = row + common.in2_pad_cumv_sel2_rowlow - 1;
					ori_col = col + common.in2_pad_cumv_sel2_collow - 1;
					d_unique_d_in2_sub_cumh[ei_new] = d_unique_d_in2_pad_cumv[ori_col*common.in2_pad_cumv_rows+ori_row];
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in2_sub_cumh_elem){
					d_unique_d_in2_sub_cumh[ei_new] = d_unique_d_in2_pad_cumv_sel[ei_new] - d_unique_d_in2_sub_cumh[ei_new];
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in2_sub_cumh_rows){
					pos_ori = ei_new;
					sum = 0;
					for(position = pos_ori; position < pos_ori+common.in2_sub_cumh_elem; position = position + common.in2_sub_cumh_rows){
						d_unique_d_in2_sub_cumh[position] = d_unique_d_in2_sub_cumh[position] + sum;
						sum = d_unique_d_in2_sub_cumh[position];
					}
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in2_sub_cumh_sel_elem){
					row = (ei_new+1) % common.in2_sub_cumh_sel_rows - 1;
					col = (ei_new+1) / common.in2_sub_cumh_sel_rows + 1 - 1;
					if((ei_new+1) % common.in2_sub_cumh_sel_rows == 0){
						row = common.in2_sub_cumh_sel_rows - 1;
						col = col - 1;
					}
					ori_row = row + common.in2_sub_cumh_sel_rowlow - 1;
					ori_col = col + common.in2_sub_cumh_sel_collow - 1;
					d_unique_d_in2_sub_cumh_sel[ei_new] = d_unique_d_in2_sub_cumh[ori_col*common.in2_sub_cumh_rows+ori_row];
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in2_sub2_elem){
					row = (ei_new+1) % common.in2_sub2_rows - 1;
					col = (ei_new+1) / common.in2_sub2_rows + 1 - 1;
					if((ei_new+1) % common.in2_sub2_rows == 0){
						row = common.in2_sub2_rows - 1;
						col = col-1;
					}
					ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
					ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
					d_unique_d_in2_sub2[ei_new] = d_unique_d_in2_sub_cumh[ori_col*common.in2_sub_cumh_rows+ori_row];
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in2_sub2_elem){
					d_unique_d_in2_sub2[ei_new] = d_unique_d_in2_sub_cumh_sel[ei_new] - d_unique_d_in2_sub2[ei_new];
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in2_sqr_elem){
					temp = d_unique_d_in2[ei_new];
					d_unique_d_in2_sqr[ei_new] = temp * temp;
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in2_pad_cumv_elem){
					row = (ei_new+1) % common.in2_pad_cumv_rows - 1;
					col = (ei_new+1) / common.in2_pad_cumv_rows + 1 - 1;
					if((ei_new+1) % common.in2_pad_cumv_rows == 0){
						row = common.in2_pad_cumv_rows - 1;
						col = col-1;
					}
					if(row > (common.in2_pad_add_rows-1) && row < (common.in2_pad_add_rows+common.in2_sqr_rows) && 
					   col > (common.in2_pad_add_cols-1) && col < (common.in2_pad_add_cols+common.in2_sqr_cols)){
						ori_row = row - common.in2_pad_add_rows;
						ori_col = col - common.in2_pad_add_cols;
						d_unique_d_in2_pad_cumv[ei_new] = d_unique_d_in2_sqr[ori_col*common.in2_sqr_rows+ori_row];
					}
					else{
						d_unique_d_in2_pad_cumv[ei_new] = 0;
					}
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in2_pad_cumv_cols){
					pos_ori = ei_new*common.in2_pad_cumv_rows;
					sum = 0;
					for(position = pos_ori; position < pos_ori+common.in2_pad_cumv_rows; position = position + 1){
						d_unique_d_in2_pad_cumv[position] = d_unique_d_in2_pad_cumv[position] + sum;
						sum = d_unique_d_in2_pad_cumv[position];
					}
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in2_pad_cumv_sel_elem){
					row = (ei_new+1) % common.in2_pad_cumv_sel_rows - 1;
					col = (ei_new+1) / common.in2_pad_cumv_sel_rows + 1 - 1;
					if((ei_new+1) % common.in2_pad_cumv_sel_rows == 0){
						row = common.in2_pad_cumv_sel_rows - 1;
						col = col-1;
					}
					ori_row = row + common.in2_pad_cumv_sel_rowlow - 1;
					ori_col = col + common.in2_pad_cumv_sel_collow - 1;
					d_unique_d_in2_pad_cumv_sel[ei_new] = d_unique_d_in2_pad_cumv[ori_col*common.in2_pad_cumv_rows+ori_row];
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in2_sub_cumh_elem){
					row = (ei_new+1) % common.in2_sub_cumh_rows - 1;
					col = (ei_new+1) / common.in2_sub_cumh_rows + 1 - 1;
					if((ei_new+1) % common.in2_sub_cumh_rows == 0){
						row = common.in2_sub_cumh_rows - 1;
						col = col-1;
					}
					ori_row = row + common.in2_pad_cumv_sel2_rowlow - 1;
					ori_col = col + common.in2_pad_cumv_sel2_collow - 1;
					d_unique_d_in2_sub_cumh[ei_new] = d_unique_d_in2_pad_cumv[ori_col*common.in2_pad_cumv_rows+ori_row];
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in2_sub_cumh_elem){
					d_unique_d_in2_sub_cumh[ei_new] = d_unique_d_in2_pad_cumv_sel[ei_new] - d_unique_d_in2_sub_cumh[ei_new];
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in2_sub_cumh_rows){
					pos_ori = ei_new;
					sum = 0;
					for(position = pos_ori; position < pos_ori+common.in2_sub_cumh_elem; position = position + common.in2_sub_cumh_rows){
						d_unique_d_in2_sub_cumh[position] = d_unique_d_in2_sub_cumh[position] + sum;
						sum = d_unique_d_in2_sub_cumh[position];
					}
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in2_sub_cumh_sel_elem){
					row = (ei_new+1) % common.in2_sub_cumh_sel_rows - 1;
					col = (ei_new+1) / common.in2_sub_cumh_sel_rows + 1 - 1;
					if((ei_new+1) % common.in2_sub_cumh_sel_rows == 0){
						row = common.in2_sub_cumh_sel_rows - 1;
						col = col - 1;
					}
					ori_row = row + common.in2_sub_cumh_sel_rowlow - 1;
					ori_col = col + common.in2_sub_cumh_sel_collow - 1;
					d_unique_d_in2_sub_cumh_sel[ei_new] = d_unique_d_in2_sub_cumh[ori_col*common.in2_sub_cumh_rows+ori_row];
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in2_sub2_elem){
					row = (ei_new+1) % common.in2_sub2_rows - 1;
					col = (ei_new+1) / common.in2_sub2_rows + 1 - 1;
					if((ei_new+1) % common.in2_sub2_rows == 0){
						row = common.in2_sub2_rows - 1;
						col = col-1;
					}
					ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
					ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
					d_unique_d_in2_sqr_sub2[ei_new] = d_unique_d_in2_sub_cumh[ori_col*common.in2_sub_cumh_rows+ori_row];
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in2_sub2_elem){
					d_unique_d_in2_sqr_sub2[ei_new] = d_unique_d_in2_sub_cumh_sel[ei_new] - d_unique_d_in2_sqr_sub2[ei_new];
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in2_sub2_elem){
					temp = d_unique_d_in2_sub2[ei_new];
					temp2 = d_unique_d_in2_sqr_sub2[ei_new] - (temp * temp / common.in_elem);
					if(temp2 < 0){
						temp2 = 0;
					}
					d_unique_d_in2_sqr_sub2[ei_new] = sqrt(temp2);
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in_sqr_elem){
					temp = d_in[ei_new];
					d_unique_d_in_sqr[ei_new] = temp * temp;
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in_cols){
					sum = 0;
					for(i = 0; i < common.in_rows; i++){
						sum = sum + d_in[ei_new*common.in_rows+i];
					}
					in_partial_sum[ei_new] = sum;
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in_sqr_rows){
					sum = 0;
					for(i = 0; i < common.in_sqr_cols; i++){
						sum = sum + d_unique_d_in_sqr[ei_new+common.in_sqr_rows*i];
					}
					in_sqr_partial_sum[ei_new] = sum;
					ei_new = ei_new + NUMBER_THREADS;
				}

				if(tx == 0){
					in_final_sum[0] = 0;
					for(i = 0; i<common.in_cols; i++){
						in_final_sum[0] = in_final_sum[0] + in_partial_sum[i];
					}
				}else if(tx == 1){
					in_sqr_final_sum[0] = 0;
					for(i = 0; i<common.in_sqr_cols; i++){
						in_sqr_final_sum[0] = in_sqr_final_sum[0] + in_sqr_partial_sum[i];
					}
				}

				if(tx == 0){
					mean = in_final_sum[0] / common.in_elem;
					mean_sqr = mean * mean;
					variance  = (in_sqr_final_sum[0] / common.in_elem) - mean_sqr;
					deviation = sqrt(variance);
					denomT_ptr[0] = sqrt((fp)(common.in_elem-1))*deviation;
				}

				ei_new = tx;
				while(ei_new < common.in2_sub2_elem){
					d_unique_d_in2_sqr_sub2[ei_new] = d_unique_d_in2_sqr_sub2[ei_new] * denomT_ptr[0];
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.conv_elem){
					d_unique_d_conv[ei_new] = d_unique_d_conv[ei_new] - d_unique_d_in2_sub2[ei_new] * in_final_sum[0] / common.in_elem;
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.in2_sub2_elem){
					d_unique_d_in2_sqr_sub2[ei_new] = d_unique_d_conv[ei_new] / d_unique_d_in2_sqr_sub2[ei_new];
					ei_new = ei_new + NUMBER_THREADS;
				}

				cent = common.sSize + common.tSize + 1;
				if(frame_no == 0){
					tMask_row = cent + d_unique_d_Row[d_unique_point_no] - d_unique_d_Row[d_unique_point_no] - 1;
					tMask_col = cent + d_unique_d_Col[d_unique_point_no] - d_unique_d_Col[d_unique_point_no] - 1;
				}
				else{
					pointer = d_unique_point_no*common.no_frames+frame_no-1;
					tMask_row = cent + d_unique_d_tRowLoc[pointer] - d_unique_d_Row[d_unique_point_no] - 1;
					tMask_col = cent + d_unique_d_tColLoc[pointer] - d_unique_d_Col[d_unique_point_no] - 1;
				}

				ei_new = tx;
				while(ei_new < common.tMask_elem){
					location = tMask_col*common.tMask_rows + tMask_row;
					if(ei_new==location){
						d_unique_d_tMask[ei_new] = 1;
					}
					else{
						d_unique_d_tMask[ei_new] = 0;
					}
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.mask_conv_elem){
					ic = (ei_new+1) % common.mask_conv_rows;
					jc = (ei_new+1) / common.mask_conv_rows + 1;
					if((ei_new+1) % common.mask_conv_rows == 0){
						ic = common.mask_conv_rows;
						jc = jc-1;
					}
					j = jc + common.mask_conv_joffset;
					jp1 = j + 1;
					if(common.mask_cols < jp1){
						ja1 = jp1 - common.mask_cols;
					}
					else{
						ja1 = 1;
					}
					if(common.tMask_cols < j){
						ja2 = common.tMask_cols;
					}
					else{
						ja2 = j;
					}
					i = ic + common.mask_conv_ioffset;
					ip1 = i + 1;
					if(common.mask_rows < ip1){
						ia1 = ip1 - common.mask_rows;
					}
					else{
						ia1 = 1;
					}
					if(common.tMask_rows < i){
						ia2 = common.tMask_rows;
					}
					else{
						ia2 = i;
					}
					s = 0;
					for(ja=ja1; ja<=ja2; ja++){
						jb = jp1 - ja;
						for(ia=ia1; ia<=ia2; ia++){
							ib = ip1 - ia;
							s = s + d_unique_d_tMask[common.tMask_rows*(ja-1)+ia-1] * 1;
						}
					}
					d_unique_d_mask_conv[ei_new] = d_unique_d_in2_sqr_sub2[ei_new] * s;
					ei_new = ei_new + NUMBER_THREADS;
				}

				ei_new = tx;
				while(ei_new < common.mask_conv_rows){
					for(i=0; i<common.mask_conv_cols; i++){
						largest_coordinate_current = ei_new*common.mask_conv_rows+i;
						largest_value_current = fabs(d_unique_d_mask_conv[largest_coordinate_current]);
						if(largest_value_current > largest_value){
							largest_coordinate = largest_coordinate_current;
							largest_value = largest_value_current;
						}
					}
					par_max_coo[ei_new] = largest_coordinate;
					par_max_val[ei_new] = largest_value;
					ei_new = ei_new + NUMBER_THREADS;
				}

				if(tx == 0){
					for(i = 0; i < common.mask_conv_rows; i++){
						if(par_max_val[i] > fin_max_val){
							fin_max_val = par_max_val[i];
							fin_max_coo = par_max_coo[i];
						}
					}
					largest_row = (fin_max_coo+1) % common.mask_conv_rows - 1;
					largest_col = (fin_max_coo+1) / common.mask_conv_rows;
					if((fin_max_coo+1) % common.mask_conv_rows == 0){
						largest_row = common.mask_conv_rows - 1;
						largest_col = largest_col - 1;
					}
					largest_row = largest_row + 1;
					largest_col = largest_col + 1;
					offset_row = largest_row - common.in_rows - (common.sSize - common.tSize);
					offset_col = largest_col - common.in_cols - (common.sSize - common.tSize);
					pointer = d_unique_point_no*common.no_frames+frame_no;
					d_unique_d_tRowLoc[pointer] = d_unique_d_Row[d_unique_point_no] + offset_row;
					d_unique_d_tColLoc[pointer] = d_unique_d_Col[d_unique_point_no] + offset_col;
				}
			}

			if(frame_no != 0 && (frame_no)%10 == 0){
				loc_pointer = d_unique_point_no*common.no_frames+frame_no;
				d_unique_d_Row[d_unique_point_no] = d_unique_d_tRowLoc[loc_pointer];
				d_unique_d_Col[d_unique_point_no] = d_unique_d_tColLoc[loc_pointer];
				ei_new = tx;
				while(ei_new < common.in_elem){
					row = (ei_new+1) % common.in_rows - 1;
					col = (ei_new+1) / common.in_rows + 1 - 1;
					if((ei_new+1) % common.in_rows == 0){
						row = common.in_rows - 1;
						col = col-1;
					}
					ori_row = d_unique_d_Row[d_unique_point_no] - 25 + row - 1;
					ori_col = d_unique_d_Col[d_unique_point_no] - 25 + col - 1;
					ori_pointer = ori_col*common.frame_rows+ori_row;
					d_in[ei_new] = common.alpha*d_in[ei_new] + (1-common.alpha)*d_common_change_d_frame[ori_pointer];
					ei_new = ei_new + NUMBER_THREADS;
				}
			}

			free(d_unique_d_in2);
			free(d_unique_d_conv);
			free(d_unique_d_in2_pad_cumv);
			free(d_unique_d_in2_pad_cumv_sel);
			free(d_unique_d_in2_sub_cumh);
			free(d_unique_d_in2_sub_cumh_sel);
			free(d_unique_d_in2_sub2);
			free(d_unique_d_in2_sqr);
			free(d_unique_d_in2_sqr_sub2);
			free(d_unique_d_in_sqr);
			free(d_unique_d_tMask);
			free(d_unique_d_mask_conv);
			free(d_in_mod_temp);
			free(in_partial_sum);
			free(in_sqr_partial_sum);
			free(par_max_val);
			free(par_max_coo);
			free(in_final_sum);
			free(in_sqr_final_sum);
			free(denomT_ptr);
			if(bx < common.endoPoints) free(d_in);
			else free(d_in); 
		}

		free(frame);
		printf("%d ", frame_no);
		fflush(NULL);

#ifdef TEST_CHECKSUM
		checksum = (fp*)malloc(sizeof(fp) * CHECK);
		for(i=0; i<CHECK; i++) checksum[i] = 0;
		printf("CHECKSUM:\n");
		for(i=0; i<CHECK; i++){
			printf("%f ", checksum[i]);
		}
		printf("\n\n");
		free(checksum);
#endif
	}

	printf("\n");
	fflush(NULL);
}

int main(int argc, char* argv []){
	params_common common;
	common.common_mem = sizeof(params_common);
	char* video_file_name = NULL;
	char* input_file_name = NULL;
	common.frames_processed = -1;

	for (int i =0; i < argc; ++i) {
		switch (argv[i][1]) {
		case 'f':	
			if (++i < argc) {
				video_file_name = argv[i];
			} else {
				printf("Could not read argument after option %s\n", argv[i-1]);
				return 1;
			}
			break;
		case 'i':	 
			if (++i < argc) {
				input_file_name = argv[i];
			} else {
				printf("Could not read argument after option %s\n", argv[i-1]);
				return 1;
			}
			break;
		case 'h':
			printf("%s <-f video_file> <-i input_file> <-n num_frames> [-p platform_id] [-n device_id]\n", argv[0]);
			return 0;
		case 'n':   
			if (++i < argc) {
				common.frames_processed = atoi(argv[i]);
			} else {
				printf("Could not read argument after option %s\n", argv[i-1]);
				return 1;
			}
			break;
		case 'p':   
			if (++i < argc) {
				platform_id_inuse = atoi(argv[i]);
			} else {
				printf("Could not read argument after option %s\n", argv[i-1]);
				return 1;
			}
			break;
		case 'd':   
			if (++i < argc) {
				device_id_inuse = atoi(argv[i]);
			} else {
				printf("Could not read argument after option %s\n", argv[i-1]);
				return 1;
			}
			break;
		}
	}

	if (input_file_name == NULL || video_file_name == NULL) {
		printf("Input or video file name is missing\n");
		return 0;
	}

	int i;
	avi_t* frames;
	frames = (avi_t*)AVI_open_input_file(video_file_name, 1);
	if (frames == NULL)  {
		AVI_print_error((char *) "Error with AVI_open_input_file");
		return -1;
	}

	common.no_frames = AVI_video_frames(frames);
	common.frame_rows = AVI_video_height(frames);
	common.frame_cols = AVI_video_width(frames);
	common.frame_elem = common.frame_rows * common.frame_cols;
	common.frame_mem = sizeof(fp) * common.frame_elem;

	if (common.frames_processed<0 || common.frames_processed>common.no_frames){
		printf("ERROR: %d is an incorrect number of frames specified, select in the range of 0-%d\n", common.frames_processed, common.no_frames);
		return 0;
	}

	read_parameters(input_file_name, &common.tSize, &common.sSize, &common.maxMove, &common.alpha);
	read_header(input_file_name, &common.endoPoints, &common.epiPoints);
	common.allPoints = common.endoPoints + common.epiPoints;

	common.endo_mem = sizeof(int) * common.endoPoints;
	int* endoRow = (int*)malloc(common.endo_mem);
	int* endoCol = (int*)malloc(common.endo_mem);
	int* tEndoRowLoc = (int*)malloc(common.endo_mem * common.no_frames);
	int* tEndoColLoc = (int*)malloc(common.endo_mem * common.no_frames);

	common.epi_mem = sizeof(int) * common.epiPoints;
	int* epiRow = (int *)malloc(common.epi_mem);
	int* epiCol = (int *)malloc(common.epi_mem);
	int* tEpiRowLoc = (int *)malloc(common.epi_mem * common.no_frames);
	int* tEpiColLoc = (int *)malloc(common.epi_mem * common.no_frames);

	read_data(input_file_name, common.endoPoints, endoRow, endoCol, common.epiPoints, epiRow, epiCol);

	kernel_gpu_opencl_wrapper(common, endoRow, endoCol, tEndoRowLoc, tEndoColLoc, epiRow, epiCol, tEpiRowLoc, tEpiColLoc, frames);

#ifdef OUTPUT
	write_data("result.txt", common.no_frames, common.frames_processed, common.endoPoints, tEndoRowLoc, tEndoColLoc, common.epiPoints, tEpiRowLoc, tEpiColLoc);
#endif

	free(endoRow);
	free(endoCol);
	free(tEndoRowLoc);
	free(tEndoColLoc);
	free(epiRow);
	free(epiCol);
	free(tEpiRowLoc);
	free(tEpiColLoc);

	return 0;
}

#include "./main.h"
#include <omp.h>
#include <math.h>
#include <stdlib.h>

void 
kernel_gpu_opencl(	
					params_common d_common,
					fp* d_frame,					
					int d_frame_no,
					int* d_endoRow,				
					int* d_endoCol,				
					int* d_tEndoRowLoc,			
					int* d_tEndoColLoc,			
					int* d_epiRow,					
					int* d_epiCol,					
					int* d_tEpiRowLoc,				
					int* d_tEpiColLoc,
					fp* d_endoT,					
					fp* d_epiT,					
					fp* d_in2_all,					
					fp* d_conv_all,				
					fp* d_in2_pad_cumv_all,		
					fp* d_in2_pad_cumv_sel_all,	
					fp* d_in2_sub_cumh_all,		
					fp* d_in2_sub_cumh_sel_all,	
					fp* d_in2_sub2_all,			
					fp* d_in2_sqr_all,				
					fp* d_in2_sqr_sub2_all,		
					fp* d_in_sqr_all,				
					fp* d_tMask_all,				
					fp* d_mask_conv_all,
					fp* d_in_mod_temp_all,			
					fp* in_partial_sum_all,		
					fp* in_sqr_partial_sum_all,	
					fp* par_max_val_all,			
					int* par_max_coo_all,
					fp* in_final_sum_all,			
					fp* in_sqr_final_sum_all,		
					fp* denomT_all,
					fp* checksum)
{

	int rot_row;
	int rot_col;
	int in2_rowlow;
	int in2_collow;
	int ic;
	int jc;
	int jp1;
	int ja1, ja2;
	int ip1;
	int ia1, ia2;
	int ja, jb;
	int ia, ib;
	fp s;
	int i;
	int j;
	int row;
	int col;
	int ori_row;
	int ori_col;
	int position;
	fp sum;
	int pos_ori;
	fp temp;
	fp temp2;
	int location;
	int cent;
	int tMask_row; 
	int tMask_col;
	fp largest_value_current = 0;
	fp largest_value = 0;
	int largest_coordinate_current = 0;
	int largest_coordinate = 0;
	fp fin_max_val = 0;
	int fin_max_coo = 0;
	int largest_row;
	int largest_col;
	int offset_row;
	int offset_col;
	fp mean;
	fp mean_sqr;
	fp variance;
	fp deviation;
	int pointer;
	int ori_pointer;
	int loc_pointer;

	int bx;
	int ei_new;

	fp* d_common_change_d_frame = &d_frame[0];

	int d_unique_point_no;
	int* d_unique_d_Row;
	int* d_unique_d_Col;
	int* d_unique_d_tRowLoc;
	int* d_unique_d_tColLoc;
	fp* d_in;

#ifdef TEST_CHECKSUM
	for(i=0; i<CHECK; i++){
		checksum[i] = 0;
	}
#endif

#pragma omp parallel for schedule(static)
	for(bx = 0; bx < d_common.allPoints; bx++) {

		if(bx < d_common.endoPoints){
			d_unique_point_no = bx;
			d_unique_d_Row = d_endoRow;
			d_unique_d_Col = d_endoCol;
			d_unique_d_tRowLoc = d_tEndoRowLoc;
			d_unique_d_tColLoc = d_tEndoColLoc;
			d_in = &d_endoT[d_unique_point_no * d_common.in_elem];
		}
		else{
			d_unique_point_no = bx-d_common.endoPoints;
			d_unique_d_Row = d_epiRow;
			d_unique_d_Col = d_epiCol;
			d_unique_d_tRowLoc = d_tEpiRowLoc;
			d_unique_d_tColLoc = d_tEpiColLoc;
			d_in = &d_epiT[d_unique_point_no * d_common.in_elem];
		}

		fp* d_unique_d_in2 = &d_in2_all[bx*d_common.in2_elem];
		fp* d_unique_d_conv = &d_conv_all[bx*d_common.conv_elem];
		fp* d_unique_d_in2_pad_cumv = &d_in2_pad_cumv_all[bx*d_common.in2_pad_cumv_elem];
		fp* d_unique_d_in2_pad_cumv_sel = &d_in2_pad_cumv_sel_all[bx*d_common.in2_pad_cumv_sel_elem];
		fp* d_unique_d_in2_sub_cumh = &d_in2_sub_cumh_all[bx*d_common.in2_sub_cumh_elem];
		fp* d_unique_d_in2_sub_cumh_sel = &d_in2_sub_cumh_sel_all[bx*d_common.in2_sub_cumh_sel_elem];
		fp* d_unique_d_in2_sub2 = &d_in2_sub2_all[bx*d_common.in2_sub2_elem];
		fp* d_unique_d_in2_sqr = &d_in2_sqr_all[bx*d_common.in2_sqr_elem];
		fp* d_unique_d_in2_sqr_sub2 = &d_in2_sqr_sub2_all[bx*d_common.in2_sqr_sub2_elem];
		fp* d_unique_d_in_sqr = &d_in_sqr_all[bx*d_common.in_sqr_elem];
		fp* d_unique_d_tMask = &d_tMask_all[bx*d_common.tMask_elem];
		fp* d_unique_d_mask_conv = &d_mask_conv_all[bx*d_common.mask_conv_elem];

		fp* d_in_mod_temp = &d_in_mod_temp_all[bx*d_common.in_elem];
		fp* in_partial_sum = &in_partial_sum_all[bx*d_common.in_cols];
		fp* in_sqr_partial_sum = &in_sqr_partial_sum_all[bx*d_common.in_sqr_rows];
		fp* par_max_val = &par_max_val_all[bx*d_common.mask_conv_rows];
		int* par_max_coo = &par_max_coo_all[bx*d_common.mask_conv_rows];

		fp* in_final_sum = &in_final_sum_all[bx];
		fp* in_sqr_final_sum = &in_sqr_final_sum_all[bx];
		fp* denomT = &denomT_all[bx];

		if(d_frame_no == 0){

#ifdef INIT
			for(i=0; i<d_common.no_frames; i++){
				d_unique_d_tRowLoc[d_unique_point_no*d_common.no_frames+i] = 0;
				d_unique_d_tColLoc[d_unique_point_no*d_common.no_frames+i] = 0;
			}
			for(i=0; i<d_common.in_elem; i++){
				d_in[i] = 0;
			}
#endif

			pointer = d_unique_point_no*d_common.no_frames+d_frame_no;
			d_unique_d_tRowLoc[pointer] = d_unique_d_Row[d_unique_point_no];
			d_unique_d_tColLoc[pointer] = d_unique_d_Col[d_unique_point_no];

			for(ei_new = 0; ei_new < d_common.in_elem; ei_new++){
				row = (ei_new+1) % d_common.in_rows - 1;
				col = (ei_new+1) / d_common.in_rows + 1 - 1;
				if((ei_new+1) % d_common.in_rows == 0){
					row = d_common.in_rows - 1;
					col = col-1;
				}

				ori_row = d_unique_d_Row[d_unique_point_no] - 25 + row - 1;
				ori_col = d_unique_d_Col[d_unique_point_no] - 25 + col - 1;
				ori_pointer = ori_col*d_common.frame_rows+ori_row;

				d_in[col*d_common.in_rows+row] = d_common_change_d_frame[ori_pointer];
			}

#ifdef TEST_CHECKSUM
			for(i=0; i<d_common.in_elem; i++){
				checksum[0] = checksum[0]+d_in[i];
			}
#endif
		}

		if(d_frame_no != 0){

#ifdef INIT
			for(i=0; i<d_common.in2_elem; i++){ d_unique_d_in2[i] = 0; }
			for(i=0; i<d_common.conv_elem; i++){ d_unique_d_conv[i] = 0; }
			for(i=0; i<d_common.in2_pad_cumv_elem; i++){ d_unique_d_in2_pad_cumv[i] = 0; }
			for(i=0; i<d_common.in2_pad_cumv_sel_elem; i++){ d_unique_d_in2_pad_cumv_sel[i] = 0; }
			for(i=0; i<d_common.in2_sub_cumh_elem; i++){ d_unique_d_in2_sub_cumh[i] = 0; }
			for(i=0; i<d_common.in2_sub_cumh_sel_elem; i++){ d_unique_d_in2_sub_cumh_sel[i] = 0; }
			for(i=0; i<d_common.in2_sub2_elem; i++){ d_unique_d_in2_sub2[i] = 0; }
			for(i=0; i<d_common.in2_sqr_elem; i++){ d_unique_d_in2_sqr[i] = 0; }
			for(i=0; i<d_common.in2_sqr_sub2_elem; i++){ d_unique_d_in2_sqr_sub2[i] = 0; }
			for(i=0; i<d_common.in_sqr_elem; i++){ d_unique_d_in_sqr[i] = 0; }
			for(i=0; i<d_common.tMask_elem; i++){ d_unique_d_tMask[i] = 0; }
			for(i=0; i<d_common.mask_conv_elem; i++){ d_unique_d_mask_conv[i] = 0; }
			for(i=0; i<d_common.in_elem; i++){ d_in_mod_temp[i] = 0; }
			for(i=0; i<d_common.in_cols; i++){ in_partial_sum[i] = 0; }
			for(i=0; i<d_common.in_sqr_rows; i++){ in_sqr_partial_sum[i] = 0; }
			for(i=0; i<d_common.mask_conv_rows; i++){ par_max_val[i] = 0; }
			for(i=0; i<d_common.mask_conv_rows; i++){ par_max_coo[i] = 0; }
			in_final_sum[0] = 0;
			in_sqr_final_sum[0] = 0;
			denomT[0] = 0;
#endif

			in2_rowlow = d_unique_d_Row[d_unique_point_no] - d_common.sSize;
			in2_collow = d_unique_d_Col[d_unique_point_no] - d_common.sSize;

			for(ei_new = 0; ei_new < d_common.in2_elem; ei_new++){
				row = (ei_new+1) % d_common.in2_rows - 1;
				col = (ei_new+1) / d_common.in2_rows + 1 - 1;
				if((ei_new+1) % d_common.in2_rows == 0){
					row = d_common.in2_rows - 1;
					col = col-1;
				}

				ori_row = row + in2_rowlow - 1;
				ori_col = col + in2_collow - 1;
				d_unique_d_in2[ei_new] = d_common_change_d_frame[ori_col*d_common.frame_rows+ori_row];
			}

#ifdef TEST_CHECKSUM
			for(i=0; i<d_common.in2_elem; i++){ checksum[1] = checksum[1]+d_unique_d_in2[i]; }
#endif

			for(ei_new = 0; ei_new < d_common.in_elem; ei_new++){
				row = (ei_new+1) % d_common.in_rows - 1;
				col = (ei_new+1) / d_common.in_rows + 1 - 1;
				if((ei_new+1) % d_common.in_rows == 0){
					row = d_common.in_rows - 1;
					col = col-1;
				}

				rot_row = (d_common.in_rows-1) - row;
				rot_col = (d_common.in_rows-1) - col;
				d_in_mod_temp[ei_new] = d_in[rot_col*d_common.in_rows+rot_row];
			}

#ifdef TEST_CHECKSUM
			for(i=0; i<d_common.in_elem; i++){ checksum[2] = checksum[2]+d_in_mod_temp[i]; }
#endif

			for(ei_new = 0; ei_new < d_common.conv_elem; ei_new++){
				ic = (ei_new+1) % d_common.conv_rows;
				jc = (ei_new+1) / d_common.conv_rows + 1;
				if((ei_new+1) % d_common.conv_rows == 0){
					ic = d_common.conv_rows;
					jc = jc-1;
				}

				j = jc + d_common.joffset;
				jp1 = j + 1;
				if(d_common.in2_cols < jp1){ ja1 = jp1 - d_common.in2_cols; } else { ja1 = 1; }
				if(d_common.in_cols < j){ ja2 = d_common.in_cols; } else { ja2 = j; }

				i = ic + d_common.ioffset;
				ip1 = i + 1;
				if(d_common.in2_rows < ip1){ ia1 = ip1 - d_common.in2_rows; } else { ia1 = 1; }
				if(d_common.in_rows < i){ ia2 = d_common.in_rows; } else { ia2 = i; }

				s = 0;
				for(ja=ja1; ja<=ja2; ja++){
					jb = jp1 - ja;
					for(ia=ia1; ia<=ia2; ia++){
						ib = ip1 - ia;
						s = s + d_in_mod_temp[d_common.in_rows*(ja-1)+ia-1] * d_unique_d_in2[d_common.in2_rows*(jb-1)+ib-1];
					}
				}
				d_unique_d_conv[ei_new] = s;
			}

#ifdef TEST_CHECKSUM
			for(i=0; i<d_common.conv_elem; i++){ checksum[3] = checksum[3]+d_unique_d_conv[i]; }
#endif

			for(ei_new = 0; ei_new < d_common.in2_pad_cumv_elem; ei_new++){
				row = (ei_new+1) % d_common.in2_pad_cumv_rows - 1;
				col = (ei_new+1) / d_common.in2_pad_cumv_rows + 1 - 1;
				if((ei_new+1) % d_common.in2_pad_cumv_rows == 0){
					row = d_common.in2_pad_cumv_rows - 1;
					col = col-1;
				}

				if(	row > (d_common.in2_pad_add_rows-1) &&
					row < (d_common.in2_pad_add_rows+d_common.in2_rows) && 
					col > (d_common.in2_pad_add_cols-1) && 
					col < (d_common.in2_pad_add_cols+d_common.in2_cols)){
					ori_row = row - d_common.in2_pad_add_rows;
					ori_col = col - d_common.in2_pad_add_cols;
					d_unique_d_in2_pad_cumv[ei_new] = d_unique_d_in2[ori_col*d_common.in2_rows+ori_row];
				}
				else{
					d_unique_d_in2_pad_cumv[ei_new] = 0;
				}
			}

#ifdef TEST_CHECKSUM
			for(i=0; i<d_common.in2_pad_cumv_elem; i++){ checksum[4] = checksum[4]+d_unique_d_in2_pad_cumv[i]; }
#endif

			for(ei_new = 0; ei_new < d_common.in2_pad_cumv_cols; ei_new++){
				pos_ori = ei_new*d_common.in2_pad_cumv_rows;
				sum = 0;
				for(position = pos_ori; position < pos_ori+d_common.in2_pad_cumv_rows; position = position + 1){
					d_unique_d_in2_pad_cumv[position] = d_unique_d_in2_pad_cumv[position] + sum;
					sum = d_unique_d_in2_pad_cumv[position];
				}
			}

#ifdef TEST_CHECKSUM
			for(i=0; i<d_common.in2_pad_cumv_cols; i++){ checksum[5] = checksum[5]+d_unique_d_in2_pad_cumv[i]; }
#endif

			for(ei_new = 0; ei_new < d_common.in2_pad_cumv_sel_elem; ei_new++){
				row = (ei_new+1) % d_common.in2_pad_cumv_sel_rows - 1;
				col = (ei_new+1) / d_common.in2_pad_cumv_sel_rows + 1 - 1;
				if((ei_new+1) % d_common.in2_pad_cumv_sel_rows == 0){
					row = d_common.in2_pad_cumv_sel_rows - 1;
					col = col-1;
				}

				ori_row = row + d_common.in2_pad_cumv_sel_rowlow - 1;
				ori_col = col + d_common.in2_pad_cumv_sel_collow - 1;
				d_unique_d_in2_pad_cumv_sel[ei_new] = d_unique_d_in2_pad_cumv[ori_col*d_common.in2_pad_cumv_rows+ori_row];
			}

#ifdef TEST_CHECKSUM
			for(i=0; i<d_common.in2_pad_cumv_sel_elem; i++){ checksum[6] = checksum[6]+d_unique_d_in2_pad_cumv_sel[i]; }
#endif

			for(ei_new = 0; ei_new < d_common.in2_sub_cumh_elem; ei_new++){
				row = (ei_new+1) % d_common.in2_sub_cumh_rows - 1;
				col = (ei_new+1) / d_common.in2_sub_cumh_rows + 1 - 1;
				if((ei_new+1) % d_common.in2_sub_cumh_rows == 0){
					row = d_common.in2_sub_cumh_rows - 1;
					col = col-1;
				}

				ori_row = row + d_common.in2_pad_cumv_sel2_rowlow - 1;
				ori_col = col + d_common.in2_pad_cumv_sel2_collow - 1;
				d_unique_d_in2_sub_cumh[ei_new] = d_unique_d_in2_pad_cumv[ori_col*d_common.in2_pad_cumv_rows+ori_row];
			}

#ifdef TEST_CHECKSUM
			for(i=0; i<d_common.in2_sub_cumh_elem; i++){ checksum[7] = checksum[7]+d_unique_d_in2_sub_cumh[i]; }
#endif

			for(ei_new = 0; ei_new < d_common.in2_sub_cumh_elem; ei_new++){
				d_unique_d_in2_sub_cumh[ei_new] = d_unique_d_in2_pad_cumv_sel[ei_new] - d_unique_d_in2_sub_cumh[ei_new];
			}

#ifdef TEST_CHECKSUM
			for(i=0; i<d_common.in2_sub_cumh_elem; i++){ checksum[8] = checksum[8]+d_unique_d_in2_sub_cumh[i]; }
#endif

			for(ei_new = 0; ei_new < d_common.in2_sub_cumh_rows; ei_new++){
				pos_ori = ei_new;
				sum = 0;
				for(position = pos_ori; position < pos_ori+d_common.in2_sub_cumh_elem; position = position + d_common.in2_sub_cumh_rows){
					d_unique_d_in2_sub_cumh[position] = d_unique_d_in2_sub_cumh[position] + sum;
					sum = d_unique_d_in2_sub_cumh[position];
				}
			}

#ifdef TEST_CHECKSUM
			for(i=0; i<d_common.in2_sub_cumh_elem; i++){ checksum[9] = checksum[9]+d_unique_d_in2_sub_cumh[i]; }
#endif

			for(ei_new = 0; ei_new < d_common.in2_sub_cumh_sel_elem; ei_new++){
				row = (ei_new+1) % d_common.in2_sub_cumh_sel_rows - 1;
				col = (ei_new+1) / d_common.in2_sub_cumh_sel_rows + 1 - 1;
				if((ei_new+1) % d_common.in2_sub_cumh_sel_rows == 0){
					row = d_common.in2_sub_cumh_sel_rows - 1;
