void hotspotOpt1(float *p, float *tIn, float *tOut, float sdc,
                 int nx, int ny, int nz,
                 float ce, float cw, 
                 float cn, float cs,
                 float ct, float cb, 
                 float cc) 
{
  float amb_temp_local = 80.0;
  int xy = nx * ny;

  #pragma omp parallel for collapse(2)
  for (int j = 0; j < ny; j++) {
    for (int i = 0; i < nx; i++) {
      int c = i + j * nx;

      int W = (i == 0)        ? c : c - 1;
      int E = (i == nx-1)     ? c : c + 1;
      int N = (j == 0)        ? c : c - nx;
      int S = (j == ny-1)     ? c : c + nx;

      float temp1, temp2, temp3;
      temp1 = temp2 = tIn[c];
      temp3 = tIn[c+xy];
      tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
        + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp_local;

      int c_k = c + xy;
      int W_k = W + xy;
      int E_k = E + xy;
      int N_k = N + xy;
      int S_k = S + xy;

      for (int k = 1; k < nz-1; ++k) {
          temp1 = temp2;
          temp2 = temp3;
          temp3 = tIn[c_k+xy];
          tOut[c_k] = cc * temp2 + cw * tIn[W_k] + ce * tIn[E_k] + cs * tIn[S_k]
            + cn * tIn[N_k] + cb * temp1 + ct * temp3 + sdc * p[c_k] + ct * amb_temp_local;
          c_k += xy;
          W_k += xy;
          E_k += xy;
          N_k += xy;
          S_k += xy;
      }
      temp1 = temp2;
      temp2 = temp3;
      tOut[c_k] = cc * temp2 + cw * tIn[W_k] + ce * tIn[E_k] + cs * tIn[S_k]
        + cn * tIn[N_k] + cb * temp1 + ct * temp3 + sdc * p[c_k] + ct * amb_temp_local;
    }
  }
}

