void fatal(char *s)
{
  fprintf(stderr, "Error: %s\n", s);
}

char *load_kernel_source(const char *filename) {
    FILE *file = fopen(filename, "r");
    if (file == NULL) fatal("Error opening kernel source file\n");
    if (fseek(file, 0, SEEK_END)) fatal("Error reading kernel source file\n");
    size_t size = ftell(file);
    char *source = (char *) malloc(size + 1);
    fseek(file, 0, SEEK_SET);
    if (fread(source, 1, size, file) != size) fatal("Error reading kernel source file\n");
    source[size] = '\0';
    return source;
}

void readinput(float *vect, int grid_rows, int grid_cols, int layers, char *file) {
    int i,j,k;
    FILE *fp;
    char str[STR_SIZE];
    float val;

    if( (fp  = fopen(file, "r" )) ==0 )
      fatal( "The file was not opened" );

    for (i=0; i <= grid_rows-1; i++)
      for (j=0; j <= grid_cols-1; j++)
        for (k=0; k <= layers-1; k++)
          {
            if (fgets(str, STR_SIZE, fp) == NULL) fatal("Error reading file\n");
            if (feof(fp))
              fatal("not enough lines in file");
            if ((sscanf(str, "%f", &val) != 1))
              fatal("invalid file format");
            vect[i*grid_cols+j+k*grid_rows*grid_cols] = val;
          }
    fclose(fp);
}

void writeoutput(float *vect, int grid_rows, int grid_cols, int layers, char *file) {
    int i,j,k, index=0;
    FILE *fp;
    char str[STR_SIZE];

    if( (fp = fopen(file, "w" )) == 0 )
      printf( "The file was not opened\n" );

    for (i=0; i < grid_rows; i++)
      for (j=0; j < grid_cols; j++)
        for (k=0; k < layers; k++)
          {
            sprintf(str, "%d\t%g\n", index, vect[i*grid_cols+j+k*grid_rows*grid_cols]);
            fputs(str,fp);
            index++;
          }
    fclose(fp);
}

void computeTempCPU(float *pIn, float* tIn, float *tOut,
        int nx, int ny, int nz, float Cap,
        float Rx, float Ry, float Rz,
        float dt, float amb_temp, int numiter)
{   float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw =stepDivCap/ Rx;
    cn = cs =stepDivCap/ Ry;
    ct = cb =stepDivCap/ Rz;

    cc = 1.0 - (2.0*ce + 2.0*cn + 3.0*ct);

    int c,w,e,n,s,b,t;
    int x,y,z;
    int i = 0;
    do{
        for(z = 0; z < nz; z++)
            for(y = 0; y < ny; y++)
                for(x = 0; x < nx; x++)
                {
                    c = x + y * nx + z * nx * ny;

                    w = (x == 0) ? c : c - 1;
                    e = (x == nx - 1) ? c : c + 1;
                    n = (y == 0) ? c : c - nx;
                    s = (y == ny - 1) ? c : c + nx;
                    b = (z == 0) ? c : c - nx * ny;
                    t = (z == nz - 1) ? c : c + nx * ny;

                    tOut[c] = tIn[c]*cc + tIn[n]*cn + tIn[s]*cs + tIn[e]*ce + tIn[w]*cw + tIn[t]*ct + tIn[b]*cb + (dt/Cap) * pIn[c] + ct*amb_temp;
                }
        float *temp = tIn;
        tIn = tOut;
        tOut = temp;
        i++;
    }
    while(i < numiter);
}

float accuracy(float *arr1, float *arr2, int len)
{
    float err = 0.0;
    int i;
    for(i = 0; i < len; i++)
    {
        err += (arr1[i]-arr2[i]) * (arr1[i]-arr2[i]);
    }
    return (float)sqrt(err/len);
}

void hotspotOpt1(float *p, float *tIn, float *tOut, float sdc,
                 int nx, int ny, int nz,
                 float ce, float cw,
                 float cn, float cs,
                 float ct, float cb,
                 float cc)
{
  float amb_temp = 80.0;
  int xy = nx * ny;

  #pragma omp parallel for collapse(2)
  for (int j = 0; j < ny; ++j) {
    for (int i = 0; i < nx; ++i) {
      int c = i + j * nx;

      int W = (i == 0)        ? c : c - 1;
      int E = (i == nx-1)     ? c : c + 1;
      int N = (j == 0)        ? c : c - nx;
      int S = (j == ny-1)     ? c : c + nx;

      float temp1, temp2, temp3;
      temp1 = temp2 = tIn[c];
      temp3 = tIn[c+xy];
      tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
        + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;

      int curr_c = c + xy;
      int curr_W = W + xy;
      int curr_E = E + xy;
      int curr_N = N + xy;
      int curr_S = S + xy;

      for (int k = 1; k < nz-1; ++k) {
          temp1 = temp2;
          temp2 = temp3;
          temp3 = tIn[curr_c+xy];
          tOut[curr_c] = cc * temp2 + cw * tIn[curr_W] + ce * tIn[curr_E] + cs * tIn[curr_S]
            + cn * tIn[curr_N] + cb * temp1 + ct * temp3 + sdc * p[curr_c] + ct * amb_temp;
          curr_c += xy;
          curr_W += xy;
          curr_E += xy;
          curr_N += xy;
          curr_S += xy;
      }
      temp1 = temp2;
      temp2 = temp3;
      tOut[curr_c] = cc * temp2 + cw * tIn[curr_W] + ce * tIn[curr_E] + cs * tIn[curr_S]
        + cn * tIn[curr_N] + cb * temp1 + ct * temp3 + sdc * p[curr_c] + ct * amb_temp;
    }
  }
}

int main(int argc, char** argv)
{
    char *pfile = NULL, *tfile = NULL, *ofile = NULL;
    int iterations = 0;
    int numCols    = 0;
    int numRows    = 0;
    int layers     = 0;

    int platform_id_inuse = 0;
    int device_id_inuse = 0;

    int cur_arg;
    for (cur_arg = 1; cur_arg<argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-h") == 0) {
            usage(argc, argv);
        }
        else if (strcmp(argv[cur_arg], "-n") == 0) {
            if (argc >= cur_arg + 1) {
                numCols = numRows = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-l") == 0) {
            if (argc >= cur_arg + 1) {
                layers = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-i") == 0) {
            if (argc >= cur_arg + 1) {
                iterations = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-f") == 0) {
            if (argc >= cur_arg + 3) {
                pfile = argv[cur_arg+1];
                tfile = argv[cur_arg+2];
                ofile = argv[cur_arg+3];
                cur_arg += 3;
            }
        }
        else if (strcmp(argv[cur_arg], "-p") == 0) {
            if (argc >= cur_arg + 1) {
                platform_id_inuse = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-d") == 0) {
            if (argc >= cur_arg + 1) {
                device_id_inuse = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
    }

    if (numCols == 0 || layers == 0 || iterations == 0 || pfile == NULL) {
        usage(argc, argv);
    }

    float dx         = chip_height/numRows;
    float dy         = chip_width/numCols;
    float dz         = t_chip/layers;

    float Cap        = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * dx * dy;
    float Rx         = dy / (2.0 * K_SI * t_chip * dx);
    float Ry         = dx / (2.0 * K_SI * t_chip * dy);
    float Rz         = dz / (K_SI * dx * dy);

    float max_slope  = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    float dt         = PRECISION / max_slope;

    float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce               = cw                                              = stepDivCap/ Rx;
    cn               = cs                                              = stepDivCap/ Ry;
    ct               = cb                                              = stepDivCap/ Rz;

    cc               = 1.0 - (2.0*ce + 2.0*cn + 3.0*ct);

    int size = numCols * numRows * layers;
    float*        tIn      = (float*) calloc(size,sizeof(float));
    float*        pIn      = (float*) calloc(size,sizeof(float));
    float*        tempCopy = (float*)malloc(size * sizeof(float));
    float*        tempOut  = (float*) calloc(size,sizeof(float));

    readinput(tIn,numRows, numCols, layers, tfile);
    readinput(pIn,numRows, numCols, layers, pfile);

    memcpy(tempCopy,tIn, size * sizeof(float));

    cl_device_id     device_id;
    cl_context       context;
    cl_command_queue commands;
    cl_program       program;
    cl_kernel        ko_vadd;

    cl_mem d_a;
    cl_mem d_b;
    cl_mem d_c;
    const char *KernelSource = load_kernel_source("hotspotKernel.cl");
    cl_uint numPlatforms;

#ifdef TIMING
    struct timeval tv;
    struct timeval tv_total_start, tv_total_end;
    struct timeval tv_init_end;
    struct timeval tv_h2d_start, tv_h2d_end;
    struct timeval tv_d2h_start, tv_d2h_end;
    struct timeval tv_kernel_start, tv_kernel_end;
    struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
              d2h_time = 0, close_time = 0, total_time = 0;

    gettimeofday(&tv_total_start, NULL);
#endif

    int err = clGetPlatformIDs(0, NULL, &numPlatforms);
    if (err != CL_SUCCESS || numPlatforms <= 0)
    {
      printf("Error: Failed to find a platform!\n%s\n",err_code(err));
      return EXIT_FAILURE;
    }

    cl_platform_id Platform[numPlatforms];
    err = clGetPlatformIDs(numPlatforms, Platform, NULL);
    if (err != CL_SUCCESS || numPlatforms <= 0)
    {
      printf("Error: Failed to get the platform!\n%s\n",err_code(err));
      return EXIT_FAILURE;
    }

    cl_uint num_devices;
    err = clGetDeviceIDs(Platform[platform_id_inuse], CL_DEVICE_TYPE_ALL, 0,
            NULL, &num_devices);
    if (err != CL_SUCCESS) {
        printf("ERROR: clGetDeviceIDs failed\n");
        return EXIT_FAILURE;
    };
    printf("num_devices = %d\n", num_devices);
    if (device_id_inuse > num_devices) {
        printf("Invalid Device Number\n");
        return EXIT_FAILURE;
    }
    cl_device_id *device_list = (cl_device_id *)malloc(sizeof(cl_device_id)*num_devices);
    if ( !device_list ) {
        printf("ERROR: new cl_device_id[] failed\n");
        return EXIT_FAILURE;
    }
    err = clGetDeviceIDs(Platform[platform_id_inuse], CL_DEVICE_TYPE_ALL, num_devices,
            device_list, NULL);
    if (err != CL_SUCCESS) {
        printf("ERROR: clGetDeviceIDs failed\n");
        return EXIT_FAILURE;
    };
    device_id = device_list[device_id_inuse];
    free(device_list);
    err = output_device_info(device_id);

    context = clCreateContext(0, 1, &device_id, NULL, NULL, &err);
    if (!context)
    {
      printf("Error: Failed to create a compute context!\n%s\n", err_code(err));
      return EXIT_FAILURE;
    }

#ifdef TIMING
    commands = clCreateCommandQueue(context, device_id, CL_QUEUE_PROFILING_ENABLE, &err);
#else
    commands = clCreateCommandQueue(context, device_id, 0, &err);
#endif
    if (!commands)
    {
      printf("Error: Failed to create a command commands!\n%s\n", err_code(err));
      return EXIT_FAILURE;
    }

    program = clCreateProgramWithSource(context, 1, (const char **) & KernelSource, NULL, &err);
    if (!program)
    {
      printf("Error: Failed to create compute program!\n%s\n", err_code(err));
      return EXIT_FAILURE;
    }

    err = clBuildProgram(program, 0, NULL, NULL, NULL, NULL);
    if (err != CL_SUCCESS)
    {
      size_t len;
      char buffer[2048];

      printf("Error: Failed to build program executable!\n%s\n", err_code(err));
      clGetProgramBuildInfo(program, device_id, CL_PROGRAM_BUILD_LOG, sizeof(buffer), buffer, &len);
      printf("%s\n", buffer);
      return EXIT_FAILURE;
    }

    ko_vadd = clCreateKernel(program, "hotspotOpt1", &err);
    if (!ko_vadd || err != CL_SUCCESS)
    {
      printf("Error: Failed to create compute kernel!\n%s\n", err_code(err));
      return EXIT_FAILURE;
    }
#ifdef  TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    d_a  = clCreateBuffer(context, CL_MEM_READ_WRITE, sizeof(float) * count, NULL, NULL);
    d_b  = clCreateBuffer(context, CL_MEM_READ_ONLY , sizeof(float) * count, NULL, NULL);
    d_c  = clCreateBuffer(context, CL_MEM_READ_WRITE, sizeof(float) * count, NULL, NULL);
#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    if (!d_a || !d_b || !d_c)
    {
      printf("Error: Failed to allocate device memory!\n");
      exit(1);
    }

    cl_event event;
    err = clEnqueueWriteBuffer(commands, d_a, CL_TRUE, 0, sizeof(float) * count, tIn, 0, NULL, &event);
    if (err != CL_SUCCESS)
    {
      printf("Error: Failed to write tIn to source array!\n%s\n", err_code(err));
      exit(1);
    }
#ifdef TIMING
    h2d_time += probe_event_time(event, commands);
#endif
    clReleaseEvent(event);

    err = clEnqueueWriteBuffer(commands, d_b, CL_TRUE, 0, sizeof(float) * count, pIn, 0, NULL, &event);
    if (err != CL_SUCCESS)
    {
      printf("Error: Failed to write pIn to source array!\n%s\n", err_code(err));
      exit(1);
    }
#ifdef TIMING
    h2d_time += probe_event_time(event, commands);
#endif
    clReleaseEvent(event);

    err = clEnqueueWriteBuffer(commands, d_c, CL_TRUE, 0, sizeof(float) * count, tempOut, 0, NULL, &event);
    if (err != CL_SUCCESS)
    {
      printf("Error: Failed to write tempOut to source array!\n%s\n", err_code(err));
      exit(1);
    }
#ifdef TIMING
    h2d_time += probe_event_time(event, commands);
#endif
    clReleaseEvent(event);

    int j;
    for(j = 0; j < iterations; j++)
    {
      // OpenMP version: call the parallel function directly instead of launching OpenCL kernel
      // We need to swap buffers manually as done in the OpenCL version
      // At start of iteration: tIn is in d_a (mapped to tIn array), pIn in d_b, output to d_c (tempOut)
      // But since we are translating to OpenMP, we operate directly on host arrays

      // For the first iteration, tIn holds initial temp, pIn holds power
      // We compute into tempOut

      // However, the OpenCL code swaps d_a and d_c. 
      // d_a starts as tIn. d_c starts as tempOut (zeros or copy).
      // After kernel, d_a becomes old d_c (output), d_c becomes old d_a (input for next).
      // So we need to manage our host arrays similarly.

      // Let's use tIn as current input, tempOut as current output.
      // After computation, swap them.

      hotspotOpt1(pIn, tIn, tempOut, stepDivCap, numCols, numRows, layers, ce, cw, cn, cs, ct, cb, cc);

      // Swap tIn and tempOut for next iteration
      float *temp = tIn;
      tIn = tempOut;
      tempOut = temp;

      // Note: In the OpenCL code, d_a (input) becomes d_c (output) then swapped.
      // Here tIn (input) becomes tempOut (output) then swapped.
      // The logic matches.
    }

    // After loop, the result is in the array that was last written to.
    // Since we swapped at the end of each iteration, the last written data is in 'tIn' 
    // because: 
    // Iter 0: write to tempOut, swap (tIn points to result)
    // Iter 1: write to tempOut (which is old tIn), swap (tIn points to result)
    // So final result is in tIn.

    // Copy result to tempOut for consistency with original code's output variable
    memcpy(tempOut, tIn, size * sizeof(float));

    clFinish(commands);
    err = clEnqueueReadBuffer( commands, d_c, CL_TRUE, 0, sizeof(float) * count, tempOut, 0, NULL, &event);
    if (err != CL_SUCCESS)
    {
      printf("Error: Failed to read output array!\n%s\n", err_code(err));
      exit(1);
    }
#ifdef TIMING
    d2h_time += probe_event_time(event, commands);
#endif
    clReleaseEvent(event);

#ifdef  TIMING
    gettimeofday(&tv_close_start, NULL);
#endif
    clReleaseMemObject(d_a);
    clReleaseMemObject(d_b);
    clReleaseMemObject(d_c);
    clReleaseProgram(program);
    clReleaseKernel(ko_vadd);
    clReleaseCommandQueue(commands);
    clReleaseContext(context);
#ifdef  TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    float* answer = (float*)calloc(size, sizeof(float));
    computeTempCPU(pIn, tempCopy, answer, numCols, numRows, layers, Cap, Rx, Ry, Rz, dt, amb_temp, iterations);
    float acc = accuracy(tempOut,answer,numRows*numCols*layers);
    printf("Accuracy: %e\n",acc);

    writeoutput(tempOut,numRows,numCols,layers,ofile);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <omp.h>

#ifndef DEVICE
#define DEVICE CL_DEVICE_TYPE_DEFAULT
#endif

#define TOL      (0.001)
#define STR_SIZE (256)
#define MAX_PD   (3.0e6)

#define PRECISION    0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI         100

#define FACTOR_CHIP	0.5

float t_chip      = 0.0005;
float chip_height = 0.016;
float chip_width  = 0.016;
float amb_temp    = 80.0;

void usage(int argc, char **argv)
{
  fprintf(stderr, "Usage: %s <-n rows/cols> <-l layers> <-i iterations> <-f powerFile tempFile outputFile> [-p platform] [-d device]\n", argv[0]);
  fprintf(stderr, "\t<rows/cols>  - number of rows/cols in the grid (positive integer)\n");
  fprintf(stderr, "\t<layers>  - number of layers in the grid (positive integer)\n");

  fprintf(stderr, "\t<iteration> - number of iterations\n");
  fprintf(stderr, "\t<powerFile>  - name of the file containing the initial power values of each cell\n");
  fprintf(stderr, "\t<tempFile>  - name of the file containing the initial temperature values of each cell\n");
  fprintf(stderr, "\t<outputFile - output file\n");
  exit(1);
}

void readinput(float *vect, int grid_rows, int grid_cols, int layers, char *file) {
    int i,j,k;
    FILE *fp;
    char str[STR_SIZE];
    float val;

    if( (fp  = fopen(file, "r" )) ==0 ) {
      fprintf(stderr, "Error: The file was not opened\n");
      exit(1);
    }

    for (i=0; i <= grid_rows-1; i++) 
      for (j=0; j <= grid_cols-1; j++)
        for (k=0; k <= layers-1; k++)
          {
            if (fgets(str, STR_SIZE, fp) == NULL) {
                fprintf(stderr, "Error reading file\n");
                exit(1);
            }
            if (feof(fp)) {
                fprintf(stderr, "not enough lines in file\n");
                exit(1);
            }

            if ((sscanf(str, "%f", &val) != 1)) {
                fprintf(stderr, "invalid file format\n");
                exit(1);
            }
            vect[i*grid_cols+j+k*grid_rows*grid_cols] = val;
          }

    fclose(fp);	
}

void writeoutput(float *vect, int grid_rows, int grid_cols, int layers, char *file) {
    int i,j,k, index=0;
    FILE *fp;
    char str[STR_SIZE];

    if( (fp = fopen(file, "w" )) == 0 ) {
      printf( "The file was not opened\n" );
      exit(1);
    }

    for (i=0; i < grid_rows; i++) 
      for (j=0; j < grid_cols; j++)
        for (k=0; k < layers; k++)
          {
            sprintf(str, "%d\t%g\n", index, vect[i*grid_cols+j+k*grid_rows*grid_cols]);
            fputs(str,fp);
            index++;
          }

    fclose(fp);	
}

void computeTempCPU(float *pIn, float* tIn, float *tOut, 
        int nx, int ny, int nz, float Cap, 
        float Rx, float Ry, float Rz, 
        float dt, float amb_temp, int numiter) 
{   float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw =stepDivCap/ Rx;
    cn = cs =stepDivCap/ Ry;
    ct = cb =stepDivCap/ Rz;

    cc = 1.0 - (2.0*ce + 2.0*cn + 3.0*ct);

    int c,w,e,n,s,b,t;
    int x,y,z;
    int i = 0;
    do{
        for(z = 0; z < nz; z++)
            for(y = 0; y < ny; y++)
                for(x = 0; x < nx; x++)
                {
                    c = x + y * nx + z * nx * ny;

                    w = (x == 0) ? c : c - 1;
                    e = (x == nx - 1) ? c : c + 1;
                    n = (y == 0) ? c : c - nx;
                    s = (y == ny - 1) ? c : c + nx;
                    b = (z == 0) ? c : c - nx * ny;
                    t = (z == nz - 1) ? c : c + nx * ny;

                    tOut[c] = tIn[c]*cc + tIn[n]*cn + tIn[s]*cs + tIn[e]*ce + tIn[w]*cw + tIn[t]*ct + tIn[b]*cb + (dt/Cap) * pIn[c] + ct*amb_temp;
                }
        float *temp = tIn;
        tIn = tOut;
        tOut = temp; 
        i++;
    }
    while(i < numiter);
}

float accuracy(float *arr1, float *arr2, int len)
{
    float err = 0.0; 
    int i;
    for(i = 0; i < len; i++)
    {
        err += (arr1[i]-arr2[i]) * (arr1[i]-arr2[i]);
    }

    return (float)sqrt(err/len);
}

void hotspotOpt1(float *p, float *tIn, float *tOut, float sdc,
                 int nx, int ny, int nz,
                 float ce, float cw, 
                 float cn, float cs,
                 float ct, float cb, 
                 float cc) 
{
  float amb_temp = 80.0;
  int xy = nx * ny;

  #pragma omp parallel for collapse(2)
  for (int j = 0; j < ny; j++) {
    for (int i = 0; i < nx; i++) {
      int c = i + j * nx;

      int W = (i == 0)        ? c : c - 1;
      int E = (i == nx-1)     ? c : c + 1;
      int N = (j == 0)        ? c : c - nx;
      int S = (j == ny-1)     ? c : c + nx;

      float temp1, temp2, temp3;
      temp1 = temp2 = tIn[c];
      temp3 = tIn[c+xy];
      tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
        + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;

      int c_curr = c + xy;
      int W_curr = W + xy;
      int E_curr = E + xy;
      int N_curr = N + xy;
      int S_curr = S + xy;

      for (int k = 1; k < nz-1; ++k) {
          temp1 = temp2;
          temp2 = temp3;
          temp3 = tIn[c_curr+xy];
          tOut[c_curr] = cc * temp2 + cw * tIn[W_curr] + ce * tIn[E_curr] + cs * tIn[S_curr]
            + cn * tIn[N_curr] + cb * temp1 + ct * temp3 + sdc * p[c_curr] + ct * amb_temp;
          c_curr += xy;
          W_curr += xy;
          E_curr += xy;
          N_curr += xy;
          S_curr += xy;
      }
      temp1 = temp2;
      temp2 = temp3;
      tOut[c_curr] = cc * temp2 + cw * tIn[W_curr] + ce * tIn[E_curr] + cs * tIn[S_curr]
        + cn * tIn[N_curr] + cb * temp1 + ct * temp3 + sdc * p[c_curr] + ct * amb_temp;
    }
  }
}

int main(int argc, char** argv)
{
    char *pfile = NULL, *tfile = NULL, *ofile = NULL;
    int iterations = 0;
    int numCols    = 0;
    int numRows    = 0;
    int layers     = 0;

    int cur_arg;
	for (cur_arg = 1; cur_arg<argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-h") == 0) {
			usage(argc, argv);
        }
        else if (strcmp(argv[cur_arg], "-n") == 0) {
            if (argc >= cur_arg + 1) {
                numCols = numRows = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-l") == 0) {
            if (argc >= cur_arg + 1) {
                layers = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
