							   nfeatures,
							   npoints,
							   tmp_cluster_centres,
							   nclusters);

				if(rmse < min_rmse_ref){
					min_rmse_ref = rmse;			
					*min_rmse = min_rmse_ref;		
					*best_nclusters = nclusters;	
					index = i;						
				}
			}			
		}

