    for (idx = 0; idx < BLOCK_SIZE / 2; idx++) {
        array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset + idx;
        for (i = BLOCK_SIZE / 2; i < BLOCK_SIZE; i++) {
            dia[i * BLOCK_SIZE + idx] = m[array_offset];
            array_offset += matrix_dim;
        }
