	fp J_ca2cam_SLmyo;
	fp J_ca4cam_SLmyo;

	BtotDyad      = parameter[2];
	CaMKIItotDyad = parameter[3];

	Vmyo = 2.1454e-11;
	Vdyad = 1.7790e-14;
	VSL = 6.6013e-13;

	kSLmyo = 8.587e-15;
	k0Boff = 0.0014;
	k0Bon = k0Boff/0.2;
	k2Boff = k0Boff/100;
	k2Bon = k0Bon;

	k4Bon = k0Bon;

	finavalu[initvalu_offset_ecc+35] = finavalu[initvalu_offset_ecc+35] + 1e-3*JCaDyad;
	finavalu[initvalu_offset_ecc+36] = finavalu[initvalu_offset_ecc+36] + 1e-3*JCaSL;
	finavalu[initvalu_offset_ecc+37] = finavalu[initvalu_offset_ecc+37] + 1e-3*JCaCyt; 

	CaMtotDyad = initvalu[initvalu_offset_Dyad+0]
			   + initvalu[initvalu_offset_Dyad+1]
			   + initvalu[initvalu_offset_Dyad+2]
			   + initvalu[initvalu_offset_Dyad+3]
			   + initvalu[initvalu_offset_Dyad+4]
			   + initvalu[initvalu_offset_Dyad+5]
			   + CaMKIItotDyad * (  initvalu[initvalu_offset_Dyad+6]
								  + initvalu[initvalu_offset_Dyad+7]
								  + initvalu[initvalu_offset_Dyad+8]
								  + initvalu[initvalu_offset_Dyad+9])
			   + initvalu[initvalu_offset_Dyad+12]
			   + initvalu[initvalu_offset_Dyad+13]
			   + initvalu[initvalu_offset_Dyad+14];
	Bdyad = BtotDyad - CaMtotDyad;
	J_cam_dyadSL = 1e-3 * (  k0Boff*initvalu[initvalu_offset_Dyad+0] - k0Bon*Bdyad*initvalu[initvalu_offset_SL+0]);
	J_ca2cam_dyadSL = 1e-3 * (  k2Boff*initvalu[initvalu_offset_Dyad+1] - k2Bon*Bdyad*initvalu[initvalu_offset_SL+1]);
	J_ca4cam_dyadSL = 1e-3 * (  k2Boff*initvalu[initvalu_offset_Dyad+2] - k4Bon*Bdyad*initvalu[initvalu_offset_SL+2]);

	J_cam_SLmyo = kSLmyo * (  initvalu[initvalu_offset_SL+0] - initvalu[initvalu_offset_Cyt+0]);
	J_ca2cam_SLmyo = kSLmyo * (  initvalu[initvalu_offset_SL+1] - initvalu[initvalu_offset_Cyt+1]);
	J_ca4cam_SLmyo = kSLmyo * (  initvalu[initvalu_offset_SL+2] - initvalu[initvalu_offset_Cyt+2]);

	finavalu[initvalu_offset_Dyad+0] = finavalu[initvalu_offset_Dyad+0] - J_cam_dyadSL;
	finavalu[initvalu_offset_Dyad+1] = finavalu[initvalu_offset_Dyad+1] - J_ca2cam_dyadSL;
	finavalu[initvalu_offset_Dyad+2] = finavalu[initvalu_offset_Dyad+2] - J_ca4cam_dyadSL;

	finavalu[initvalu_offset_SL+0] = finavalu[initvalu_offset_SL+0] + J_cam_dyadSL*Vdyad/VSL - J_cam_SLmyo/VSL;
	finavalu[initvalu_offset_SL+1] = finavalu[initvalu_offset_SL+1] + J_ca2cam_dyadSL*Vdyad/VSL - J_ca2cam_SLmyo/VSL;
	finavalu[initvalu_offset_SL+2] = finavalu[initvalu_offset_SL+2] + J_ca4cam_dyadSL*Vdyad/VSL - J_ca4cam_SLmyo/VSL;

	finavalu[initvalu_offset_Cyt+0] = finavalu[initvalu_offset_Cyt+0] + J_cam_SLmyo/Vmyo;
	finavalu[initvalu_offset_Cyt+1] = finavalu[initvalu_offset_Cyt+1] + J_ca2cam_SLmyo/Vmyo;
	finavalu[initvalu_offset_Cyt+2] = finavalu[initvalu_offset_Cyt+2] + J_ca4cam_SLmyo/Vmyo;

}

int 
solver(fp **y,
		fp *x,
		int xmax,
		fp *params,
		fp *com,
		long long *timecopyin,
		long long *timecopykernel,
		long long *timecopyout)
{

	fp err_exponent;
	int error;
	int outside;
	fp h;
	fp h_init;
	fp tolerance;
	int xmin;

	fp scale_min;
	fp scale_fina;
	fp* err= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* scale= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* yy= (fp *) malloc(EQUATIONS* sizeof(fp));

	int i, j, k;

	err_exponent = 1.0 / 7.0;
	h_init = 1;
	h = h_init;
	xmin = 0;
	tolerance = 10 / (fp)(xmax-xmin);

	x[0] = 0;

	if (xmax < xmin || h <= 0.0){
		return -2;
	}

	if (xmax == xmin){
		return 0; 
	}

	if (h > (xmax - xmin) ) { 
		h = (fp)xmax - (fp)xmin; 
	}

	printf("Time Steps: ");
	fflush(0);

	for(k=1; k<=xmax; k++) {

		x[k] = k-1;
		h = h_init;

		scale_fina = 1.0;

		for (j = 0; j < ATTEMPTS; j++) {

			error = 0;
			outside = 0;
			scale_min = MAX_SCALE_FACTOR;

			embedded_fehlberg_7_8(	x[k],
									h,
									y[k-1],
									y[k],
									err,
									params,
									com,
									timecopyin,
									timecopykernel,
									timecopyout);

			for(i=0; i<EQUATIONS; i++){
				if(err[i] > 0){
					error = 1;
				}
			}
			if (error != 1) {
				scale_fina = MAX_SCALE_FACTOR; 
				break;
			}

			for(i=0; i<EQUATIONS; i++){
				if(y[k-1][i] == 0.0){
					yy[i] = tolerance;
				}
				else{
					yy[i] = fabs(y[k-1][i]);
				}
				scale[i] = 0.8 * pow( tolerance * yy[i] / err[i] , err_exponent );
				if(scale[i]<scale_min){
					scale_min = scale[i];
				}
			}
			scale_fina = min( max(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

			for(i=0; i<EQUATIONS; i++){
				if ( err[i] > ( tolerance * yy[i] ) ){
					outside = 1;
				}
			}
			if (outside == 0){
				break;
			}

			h = h * scale_fina;

			if (h >= 0.9) {
				h = 0.9;
			}

			if ( x[k] + h > (fp)xmax ){
				h = (fp)xmax - x[k];
			}
			else if ( x[k] + h + 0.5 * h > (fp)xmax ){
				h = 0.5 * h;
			}

		}

		x[k] = x[k] + h;

		if ( j >= ATTEMPTS ) {
			return -1; 
		}

		printf("%d ", k);
		fflush(0);

	}

	printf("\n");
	fflush(0);

	free(err);
	free(scale);
	free(yy);

	return 0;

} 

int device_id_inuse = 0;
int platform_id_inuse = 0;

int 
main(int argc, 
		char *argv []){

	int cur_arg;
	int xmax;
	int workload = 1;
    char *data_dir;

	if(argc>3){
		for(cur_arg=1; cur_arg<argc; cur_arg++){

			if(strcmp(argv[cur_arg], "-time")==0){

				if(argc>=cur_arg+1){

					char *endptr;
					long val = strtol(argv[cur_arg+1], &endptr, 10);
					if(*endptr == '\0' && argv[cur_arg+1][0] != '\0'){
						xmax = (int)val;
						if(xmax<0){
							printf("ERROR: Wrong value to -time argument, cannot be <=0\n");
							return 0;
						}
						cur_arg = cur_arg+1;
					}
					else{
						printf("ERROR: Value to -time argument in not a number\n");
						return 0;
					}
				}
				else{
					printf("ERROR: Missing value to -time argument\n");
					return 0;
				}
			}
            else if(strcmp(argv[cur_arg], "-p")==0) {
				if(argc>=cur_arg+1) {
					char *endptr;
					long val = strtol(argv[cur_arg+1], &endptr, 10);
					if(*endptr == '\0' && argv[cur_arg+1][0] != '\0') {
						platform_id_inuse = (int)val;
						cur_arg = cur_arg+1;
					}
				}
            }
            else if(strcmp(argv[cur_arg], "-d")==0) {
				if(argc>=cur_arg+1) {
					char *endptr;
					long val = strtol(argv[cur_arg+1], &endptr, 10);
					if(*endptr == '\0' && argv[cur_arg+1][0] != '\0') {
						device_id_inuse = (int)val;
						cur_arg = cur_arg+1;
					}
				}
		    }
            else if (strcmp(argv[cur_arg], "-r") == 0) {
                if (argc >= cur_arg+1) {
                    data_dir = argv[cur_arg+1];
                    cur_arg++;
                }
            }
			else{
				printf("ERROR: Unknown argument\n");
				return 0;
			}
		}
	}
	else{
		printf("Provide time argument, example: -time 100");
		return 0;
	}

	if(workload == 1){

		int i,j;

		long long memory;
		memory = workload*(xmax+1)*EQUATIONS*4;
		if(memory>1000000000){
			printf("ERROR: trying to allocate more than 1.0GB of memory, decrease workload and span parameters or change memory parameter\n");
			return 0;
		}

		fp*** y;
		y = (fp ***) malloc(workload* sizeof(fp **));
		for(i=0; i<workload; i++){
			y[i] = (fp**)malloc((1+xmax)*sizeof(fp*));
			for(j=0; j<(1+xmax); j++){
				y[i][j]= (fp *) malloc(EQUATIONS* sizeof(fp));
			}
		}

		fp** x;
		x = (fp **) malloc(workload * sizeof(fp *));
		for (i= 0; i<workload; i++){
			x[i]= (fp *)malloc((1+xmax) *sizeof(fp));
		}

		fp** params;
		params = (fp **) malloc(workload * sizeof(fp *));
		for (i= 0; i<workload; i++){
			params[i]= (fp *)malloc(PARAMETERS * sizeof(fp));
		}

		fp* com;
		com = (fp*)malloc(3 * sizeof(fp));

        char y_file[100];
        sprintf(y_file, "%s/%s", data_dir, "y.txt");
		for(i=0; i<workload; i++){
			FILE* fid = fopen(y_file, "r");
			if(fid != NULL) {
				fp temp;
				for(int r=0; r<EQUATIONS; r++) {
					fscanf(fid, "%f", &temp);
					y[i][0][r] = temp;
				}
				fclose(fid);
			}
		}

        char params_file[100];
        sprintf(params_file, "%s/%s", data_dir, "params.txt");
		for(i=0; i<workload; i++){
			FILE* fid = fopen(params_file, "r");
			if(fid != NULL) {
				fp temp;
				for(int r=0; r<PARAMETERS; r++) {
					fscanf(fid, "%f", &temp);
					params[i][r] = temp;
				}
				fclose(fid);
			}
		}

		kernel_gpu_opencl_wrapper(xmax, workload, y, x, params, com);

	  FILE * pFile;
	  pFile = fopen ("output.txt","w");
	  if (pFile==NULL) {
	    fputs ("fopen example",pFile);
	    return -1;
	  }

	  int k;
	  for(i=0; i<workload; i++){
	  fprintf(pFile, "WORKLOAD %d:\n", i);
	  for(j=0; j<(xmax+1); j++){
	  fprintf(pFile, "\tTIME %d:\n", j);
	  for(k=0; k<EQUATIONS; k++){
	  fprintf(pFile, "\t\ty[%d][%d][%d]=%10.7e\n", i, j, k, y[i][j][k]);
	}
	}
	}

	  fclose (pFile);

		for (i= 0; i< workload; i++){
			for (j= 0; j< (1+xmax); j++){
				free(y[i][j]);
			}
			free(y[i]);
		}
		free(y);

		for (i= 0; i< workload; i++){
			free(x[i]);
		}
		free(x);

		for (i= 0; i< workload; i++){
			free(params[i]);
		}
		free(params);

		free(com);

	}

	return 0;

}

int 
kernel_gpu_opencl_wrapper(int xmax,
							int workload,
							fp ***y,
							fp **x,
							fp **params,
							fp *com)
{

	long long time0;
	long long time1;
	long long time2;
	long long time3;
	long long time4;
	long long timecopyin = 0;
	long long timekernel = 0;
	long long timecopyout = 0;
	long long timeother;

	time0 = get_time();

	int i;

	time1 = get_time();

	time2 = get_time();

	int status;

	for(i=0; i<workload; i++){

		status = solver(y[i],
						x[i],
						xmax,
						params[i],
						com,
						&timecopyin,
						&timekernel,
						&timecopyout);

		if(status !=0){
			printf("STATUS: %d\n", status);
		}

	}

	time3 = get_time();

	time4= get_time();

	printf("Time spent in different stages of the application:\n");
	printf("%15.12f s, %15.12f % : CPU: GPU SETUP\n", 								(float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time4-time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: ALLOCATE GPU MEMORY\n", 					(float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time4-time0) * 100);
	printf("%15.12f s, %15.12f % : GPU: COMPUTATION\n", 							(float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time4-time0) * 100);

	printf("\tGPU: COMPUTATION Components:\n");
	printf("\t%15.12f s, %15.12f % : GPU: COPY DATA IN\n", 							(float) (timecopyin) / 1000000, (float) (timecopyin) / (float) (time4-time0) * 100);
	printf("\t%15.12f s, %15.12f % : GPU: KERNEL\n", 								(float) (timekernel) / 1000000, (float) (timekernel) / (float) (time4-time0) * 100);
	printf("\t%15.12f s, %15.12f % : GPU: COPY DATA OUT\n", 						(float) (timecopyout) / 1000000, (float) (timecopyout) / (float) (time4-time0) * 100);
	timeother = time3-time2-timecopyin-timekernel-timecopyout;
	printf("\t%15.12f s, %15.12f % : GPU: OTHER\n", 								(float) (timeother) / 1000000, (float) (timeother) / (float) (time4-time0) * 100);

	printf("%15.12f s, %15.12f % : CPU: FREE GPU MEMORY\n", 						(float) (time4-time3) / 1000000, (float) (time4-time3) / (float) (time4-time0) * 100);
	printf("Total time:\n");
	printf("%.12f s\n", 															(float) (time4-time0) / 1000000);

	return 0;

}

