	kpp1 = 1.72;
	Kmpp1 = 11.5;
	kib2 = kib;
	kb2i = kib2*5;
	kb24 = k24;
	kb42 = k42*33.5e-3/5;
	kta = kbi/1000;
	kat = kib;
	kt42 = k42*33.5e-6/5;
