		fp *initvalu,
		fp *parameter,
		fp *finavalu,
		fp *com,

		void *d_initvalu,
		void *d_finavalu,
		void *d_params,
		void *d_com,

		void *command_queue,
		void *kernel,

		long long *timecopyin,
		long long *timekernel,
		long long *timecopyout)
{
	long long time0, time1, time2, time3;
	int i;
	int initvalu_offset_ecc, initvalu_offset_Dyad, initvalu_offset_SL, initvalu_offset_Cyt;

	time0 = 0; 

	kernel_gpu_opencl((int)timeinst, (fp*)initvalu, (fp*)finavalu, (fp*)parameter, (fp*)com);

	time1 = 0;
	time2 = 0;
	time3 = 0;

	timecopyin[0] = timecopyin[0] + (time1-time0);
	timekernel[0] = timekernel[0] + (time2-time1);
	timecopyout[0] = timecopyout[0] + (time3-time2);

	initvalu_offset_ecc = 0;
	initvalu_offset_Dyad = 46;
	initvalu_offset_SL = 61;
	initvalu_offset_Cyt = 76;

	kernel_fin(initvalu,
				initvalu_offset_ecc,
				initvalu_offset_Dyad,
				initvalu_offset_SL,
				initvalu_offset_Cyt,
				parameter,
				finavalu,
				com[0],
				com[1],
				com[2]);

	for(i=0; i<EQUATIONS; i++){
		if (isnan(finavalu[i]) == 1){ 
			finavalu[i] = 0.0001;
		}
		else if (isinf(finavalu[i]) == 1){ 
			finavalu[i] = 0.0001;
		}
	}
}

