void embedded_fehlberg_7_8(fp timeinst,
						fp h,
						fp *initvalu,
						fp *finavalu,
						fp *error,
						fp *parameter,
						fp *com,
						void *d_initvalu,
						void *d_finavalu,
						void *d_params,
						void *d_com,
						void *command_queue,
						void *kernel,
						long long *timecopyin,
						long long *timecopykernel,
						long long *timecopyout) 
{
	fp h2_7 = a2 * h;
	fp timeinst_temp;
	fp* initvalu_temp;
	fp** finavalu_temp;
	int i;

	initvalu_temp= (fp *) malloc(EQUATIONS* sizeof(fp));
	finavalu_temp= (fp **) malloc(13* sizeof(fp *));
	for (i= 0; i<13; i++){
		finavalu_temp[i]= (fp *) malloc(EQUATIONS* sizeof(fp));
	}

	timeinst_temp = timeinst;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i];
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[0], com, d_initvalu, d_finavalu, d_params, d_com, command_queue, kernel, timecopyin, timecopykernel, timecopyout);

	timeinst_temp = timeinst+h2_7;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h2_7 * (finavalu_temp[0][i]);
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[1], com, d_initvalu, d_finavalu, d_params, d_com, command_queue, kernel, timecopyin, timecopykernel, timecopyout);

	timeinst_temp = timeinst+a3*h;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b31*finavalu_temp[0][i] + b32*finavalu_temp[1][i]);
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[2], com, d_initvalu, d_finavalu, d_params, d_com, command_queue, kernel, timecopyin, timecopykernel, timecopyout);

	timeinst_temp = timeinst+a4*h;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b41*finavalu_temp[0][i] + b43*finavalu_temp[2][i]);
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[3], com, d_initvalu, d_finavalu, d_params, d_com, command_queue, kernel, timecopyin, timecopykernel, timecopyout);

	timeinst_temp = timeinst+a5*h;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b51*finavalu_temp[0][i] + b53*finavalu_temp[2][i] + b54*finavalu_temp[3][i]);
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[4], com, d_initvalu, d_finavalu, d_params, d_com, command_queue, kernel, timecopyin, timecopykernel, timecopyout);

	timeinst_temp = timeinst+a6*h;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b61*finavalu_temp[0][i] + b64*finavalu_temp[3][i] + b65*finavalu_temp[4][i]);
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[5], com, d_initvalu, d_finavalu, d_params, d_com, command_queue, kernel, timecopyin, timecopykernel, timecopyout);

	timeinst_temp = timeinst+a7*h;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b71*finavalu_temp[0][i] + b74*finavalu_temp[3][i] + b75*finavalu_temp[4][i] + b76*finavalu_temp[5][i]);
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[6], com, d_initvalu, d_finavalu, d_params, d_com, command_queue, kernel, timecopyin, timecopykernel, timecopyout);

	timeinst_temp = timeinst+a8*h;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b81*finavalu_temp[0][i] + b85*finavalu_temp[4][i] + b86*finavalu_temp[5][i] + b87*finavalu_temp[6][i]);
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[7], com, d_initvalu, d_finavalu, d_params, d_com, command_queue, kernel, timecopyin, timecopykernel, timecopyout);

	timeinst_temp = timeinst+a9*h;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b91*finavalu_temp[0][i] + b94*finavalu_temp[3][i] + b95*finavalu_temp[4][i] + b96*finavalu_temp[5][i] + b97*finavalu_temp[6][i]+ b98*finavalu_temp[7][i]);
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[8], com, d_initvalu, d_finavalu, d_params, d_com, command_queue, kernel, timecopyin, timecopykernel, timecopyout);

	timeinst_temp = timeinst+a10*h;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b10_1*finavalu_temp[0][i] + b10_4*finavalu_temp[3][i] + b10_5*finavalu_temp[4][i] + b10_6*finavalu_temp[5][i] + b10_7*finavalu_temp[6][i] + b10_8*finavalu_temp[7][i] + b10_9*finavalu_temp[8][i]);
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[9], com, d_initvalu, d_finavalu, d_params, d_com, command_queue, kernel, timecopyin, timecopykernel, timecopyout);

	timeinst_temp = timeinst+h;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b11_1*finavalu_temp[0][i] + b11_4*finavalu_temp[3][i] + b11_5*finavalu_temp[4][i] + b11_6*finavalu_temp[5][i] + b11_7*finavalu_temp[6][i] + b11_8*finavalu_temp[7][i] + b11_9*finavalu_temp[8][i]+ b11_10 * finavalu_temp[9][i]);
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[10], com, d_initvalu, d_finavalu, d_params, d_com, command_queue, kernel, timecopyin, timecopykernel, timecopyout);

	timeinst_temp = timeinst;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b12_1*finavalu_temp[0][i] + b12_6*finavalu_temp[5][i] + b12_7*finavalu_temp[6][i] + b12_8*finavalu_temp[7][i] + b12_9*finavalu_temp[8][i] + b12_10 * finavalu_temp[9][i]);
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[11], com, d_initvalu, d_finavalu, d_params, d_com, command_queue, kernel, timecopyin, timecopykernel, timecopyout);

	timeinst_temp = timeinst+h;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b13_1*finavalu_temp[0][i] + b13_4*finavalu_temp[3][i] + b13_5*finavalu_temp[4][i] + b13_6*finavalu_temp[5][i] + b13_7*finavalu_temp[6][i] + b13_8*finavalu_temp[7][i] + b13_9*finavalu_temp[8][i] + b13_10*finavalu_temp[9][i] + finavalu_temp[11][i]);
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[12], com, d_initvalu, d_finavalu, d_params, d_com, command_queue, kernel, timecopyin, timecopykernel, timecopyout);

	for(i=0; i<EQUATIONS; i++){
		finavalu[i]= initvalu[i] +  h * (c_1_11 * (finavalu_temp[0][i] + finavalu_temp[10][i])  + c6 * finavalu_temp[5][i] + c_7_8 * (finavalu_temp[6][i] + finavalu_temp[7][i]) + c_9_10 * (finavalu_temp[8][i] + finavalu_temp[9][i]));
	}

	for(i=0; i<EQUATIONS; i++){
		error[i] = fabs(err_factor * (finavalu_temp[0][i] + finavalu_temp[10][i] - finavalu_temp[11][i] - finavalu_temp[12][i]));
	}

	free(initvalu_temp);
	for (i= 0; i<13; i++){
		free(finavalu_temp[i]);
	}
	free(finavalu_temp);
}

#define max(x,y) ( (x) < (y) ? (y) : (x) )
#define min(x,y) ( (x) < (y) ? (x) : (y) )

#define ATTEMPTS 12
#define MIN_SCALE_FACTOR 0.125
#define MAX_SCALE_FACTOR 4.0

int solver(fp **y,
		fp *x,
		int xmax,
		fp *params,
		fp *com,
		void *d_initvalu,
		void *d_finavalu,
		void *d_params,
		void *d_com,
		void *command_queue,
		void *kernel,
		long long *timecopyin,
		long long *timecopykernel,
		long long *timecopyout)
{
	fp err_exponent;
	int error;
	int outside;
	fp h;
	fp h_init;
	fp tolerance;
	int xmin;
	fp scale_min;
	fp scale_fina;
	fp* err= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* scale= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* yy= (fp *) malloc(EQUATIONS* sizeof(fp));
	int i, j, k;

	err_exponent = 1.0 / 7.0;
	h_init = 1;
	h = h_init;
	xmin = 0;
	tolerance = 10 / (fp)(xmax-xmin);
	x[0] = 0;

	if (xmax < xmin || h <= 0.0){
		free(err); free(scale); free(yy);
		return -2;
	}
	if (xmax == xmin){
		free(err); free(scale); free(yy);
		return 0; 
	}
	if (h > (xmax - xmin) ) { 
		h = (fp)xmax - (fp)xmin; 
	}

	printf("Time Steps: ");
	fflush(stdout);

	for(k=1; k<=xmax; k++) {
		x[k] = k-1;
		h = h_init;
		scale_fina = 1.0;

		for (j = 0; j < ATTEMPTS; j++) {
			error = 0;
			outside = 0;
			scale_min = MAX_SCALE_FACTOR;

			embedded_fehlberg_7_8(x[k], h, y[k-1], y[k], err, params, com, d_initvalu, d_finavalu, d_params, d_com, command_queue, kernel, timecopyin, timecopykernel, timecopyout);

			for(i=0; i<EQUATIONS; i++){
				if(err[i] > 0){
					error = 1;
				}
			}
			if (error != 1) {
				scale_fina = MAX_SCALE_FACTOR; 
				break;
			}

			for(i=0; i<EQUATIONS; i++){
				if(y[k-1][i] == 0.0){
					yy[i] = tolerance;
				}
				else{
					yy[i] = fabs(y[k-1][i]);
				}
				scale[i] = 0.8 * pow( tolerance * yy[i] / err[i] , err_exponent );
				if(scale[i]<scale_min){
					scale_min = scale[i];
				}
			}
			scale_fina = min( max(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

			for(i=0; i<EQUATIONS; i++){
				if ( err[i] > ( tolerance * yy[i] ) ){
					outside = 1;
				}
			}
			if (outside == 0){
				break;
			}

			h = h * scale_fina;
			if (h >= 0.9) {
				h = 0.9;
			}
			if ( x[k] + h > (fp)xmax ){
				h = (fp)xmax - x[k];
			}
			else if ( x[k] + h + 0.5 * h > (fp)xmax ){
				h = 0.5 * h;
			}
		}

		x[k] = x[k] + h;

		if ( j >= ATTEMPTS ) {
			free(err); free(scale); free(yy);
			return -1; 
		}

		printf("%d ", k);
		fflush(stdout);
	}
	printf("\n");
	fflush(stdout);

	free(err);
	free(scale);
	free(yy);

	return 0;
}

int isInteger(char *str){
	if (*str == '\0'){
		return 0;
	}
	for(; *str != '\0'; str++){
		if (*str < 48 || *str > 57){	
			return 0;
		}
	}
	return 1;
}

int kernel_gpu_opencl_wrapper(int xmax,
							int workload,
							fp ***y,
							fp **x,
							fp **params,
							fp *com)
{
	long long time0, time1, time2, time3, time4;
	long long timecopyin = 0;
	long long timekernel = 0;
	long long timecopyout = 0;
	long long timeother;
	int i;

	time0 = 0; 

	int d_initvalu_mem = EQUATIONS * sizeof(fp);
	int d_finavalu_mem = EQUATIONS * sizeof(fp);
	int d_params_mem = PARAMETERS * sizeof(fp);
	int d_com_mem = 3 * sizeof(fp);

	time1 = 0;
	time2 = 0;

	int status;
	for(i=0; i<workload; i++){
		status = solver(y[i], x[i], xmax, params[i], com, NULL, NULL, NULL, NULL, NULL, NULL, &timecopyin, &timekernel, &timecopyout);
		if(status !=0){
			printf("STATUS: %d\n", status);
		}
	}

	time3 = 0;
	time4 = 0;

	printf("Time spent in different stages of the application:\n");
	printf("%15.12f s, %15.12f % : CPU: GPU SETUP\n", (float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time4-time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: ALLOCATE GPU MEMORY\n", (float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time4-time0) * 100);
	printf("%15.12f s, %15.12f % : GPU: COMPUTATION\n", (float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time4-time0) * 100);
	printf("\tGPU: COMPUTATION Components:\n");
	printf("\t%15.12f s, %15.12f % : GPU: COPY DATA IN\n", (float) (timecopyin) / 1000000, (float) (timecopyin) / (float) (time4-time0) * 100);
	printf("\t%15.12f s, %15.12f % : GPU: KERNEL\n", (float) (timekernel) / 1000000, (float) (timekernel) / (float) (time4-time0) * 100);
	printf("\t%15.12f s, %15.12f % : GPU: COPY DATA OUT\n", (float) (timecopyout) / 1000000, (float) (timecopyout) / (float) (time4-time0) * 100);
	timeother = time3-time2-timecopyin-timekernel-timecopyout;
	printf("\t%15.12f s, %15.12f % : GPU: OTHER\n", (float) (timeother) / 1000000, (float) (timeother) / (float) (time4-time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: FREE GPU MEMORY\n", (float) (time4-time3) / 1000000, (float) (time4-time3) / (float) (time4-time0) * 100);
	printf("Total time:\n");
	printf("%.12f s\n", (float) (time4-time0) / 1000000);

	return 0;
}

