#include <omp.h>
#include <vector>
#include <algorithm>
#include <iostream>

#ifndef REC_LENGTH
#define REC_LENGTH 49
#endif

typedef struct latLong {
    float lat;
    float lng;
} LatLong;

typedef struct record {
    char recString[REC_LENGTH];
    float distance;
} Record;

void nearest_neighbor_kernel(LatLong *locations, float *distances, int numRecords, float lat, float lng) {
    #pragma omp parallel for
    for (int i = 0; i < numRecords; i++) {
        float diff_lat = lat - locations[i].lat;
        float diff_lng = lng - locations[i].lng;
        distances[i] = sqrt(diff_lat * diff_lat + diff_lng * diff_lng);
    }
}

float *OpenMPFindNearestNeighbors(
    int numRecords,
    std::vector<LatLong> &locations,
    float lat,
    float lng,
    int timing) {

    float *distances = (float *)malloc(sizeof(float) * numRecords);
    if (!distances) {
        fprintf(stderr, "Memory allocation failed\n");
        exit(1);
    }

    double start_time = 0.0;
    double end_time = 0.0;

    if (timing) {
        start_time = omp_get_wtime();
    }

    nearest_neighbor_kernel(&locations[0], distances, numRecords, lat, lng);

    if (timing) {
        end_time = omp_get_wtime();
        printf("Kernel execution time: %f seconds\n", end_time - start_time);
    }

    return distances;
}

int loadData(char *filename, std::vector<Record> &records, std::vector<LatLong> &locations) {
    FILE *flist, *fp;
    int i = 0;
    char dbname[64], db_fullname[128];
    int recNum = 0;

    const char* data_folder = getenv("DATA_FOLDER");
    if (!data_folder) {
        data_folder = "."; 
    }

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "Could not open filelist: %s\n", filename);
        exit(1);
    }

    while (!feof(flist)) {
        if (fscanf(flist, "%s\n", dbname) != 1) {
            if (!feof(flist)) {
                fprintf(stderr, "error reading filelist\n");
            }
            break;
        }
        snprintf(db_fullname, sizeof(db_fullname), "%s/%s", data_folder, dbname);
        fp = fopen(db_fullname, "r");
        if (!fp) {
            printf("error opening a db (%s)\n", db_fullname);
            exit(1);
        }

        while (!feof(fp)) {
            Record record;
            LatLong latLong;

            if (fgets(record.recString, REC_LENGTH, fp) == NULL) break;

            size_t len = strlen(record.recString);
            if (len > 0 && record.recString[len-1] == '\n') {
                record.recString[len-1] = '\0';
            }

            if (strlen(record.recString) < 38) continue; 

            char substr[6];

            for (i = 0; i < 5 && (28 + i) < len; i++) 
                substr[i] = record.recString[28 + i];
            substr[5] = '\0';
            latLong.lat = atof(substr);

            for (i = 0; i < 5 && (33 + i) < len; i++) 
                substr[i] = record.recString[33 + i];
            substr[5] = '\0';
            latLong.lng = atof(substr);

            locations.push_back(latLong);
            records.push_back(record);
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    return recNum;
}

void findLowest(std::vector<Record> &records, float *distances, int numRecords, int topN) {
    int i, j;
    float val;
    int minLoc;
    Record tempRec;
    float tempDist;

    for (i = 0; i < topN; i++) {
        minLoc = i;
        for (j = i; j < numRecords; j++) {
            val = distances[j];
            if (val < distances[minLoc]) minLoc = j;
        }

        if (minLoc != i) {
            tempRec = records[i];
            records[i] = records[minLoc];
            records[minLoc] = tempRec;

            tempDist = distances[i];
            distances[i] = distances[minLoc];
            distances[minLoc] = tempDist;
        }

        records[i].distance = distances[i];
    }
}

