// Simulated OpenCL local memory management for translation
struct LocalBuffers {
    int* prev;
    int* result;
    int size;

    LocalBuffers(int s) : size(s) {
        prev = new int[s];
        result = new int[s];
    }
    ~LocalBuffers() {
        delete[] prev;
        delete[] result;
    }
};

void dynproc_kernel(int iteration,
                    int* gpuWall,
                    int* gpuSrc,
                    int* gpuResults,
                    int cols,
                    int rows,
                    int startStep,
                    int border,
                    int HALO,
                    int* local_prev,
                    int* local_result,
                    int* outputBuffer,
                    int BLOCK_SIZE,
                    int bx)
{
	int tx = 0; // Thread index within block (0..BLOCK_SIZE-1)

	// We simulate the block execution for each thread in the block sequentially 
	// but parallelized across blocks using OpenMP.
	// However, OpenMP parallelizes over blocks, and inside each block we simulate threads.
	// To match OpenCL behavior exactly, we must iterate tx from 0 to BLOCK_SIZE-1.
	// But since we want parallelism, we parallelize over bx (blocks), and inside each block,
	// we run a loop over tx (threads) sequentially to maintain barrier semantics.

	// Actually, to preserve exact algorithm and barrier behavior, we cannot parallelize tx inside a block.
	// So we parallelize over bx (blocks), and inside each block, we execute all tx sequentially.

	int small_block_cols = BLOCK_SIZE - (iteration*HALO*2);
	int blkX = (small_block_cols*bx) - border;
	int blkXmax = blkX+BLOCK_SIZE-1;

	int validXmin = (blkX < 0) ? -blkX : 0;
	int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

	// Initialize local memory for all threads in this block
	for (tx = 0; tx < BLOCK_SIZE; tx++) {
		int xidx = blkX+tx;
		if(IN_RANGE(xidx, 0, cols-1))
		{
			local_prev[tx] = gpuSrc[xidx];
		}
	}
	// Barrier simulated by sequential execution in this context

	bool computed = false;
	for (int i = 0; i < iteration; i++)
	{
		computed = false;

		// Compute for valid threads
		for (tx = 0; tx < BLOCK_SIZE; tx++) {
			if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && IN_RANGE(tx, validXmin, validXmax) )
			{
				computed = true;
				int W = tx-1;
				int E = tx+1;
				W = (W < validXmin) ? validXmin : W;
				E = (E > validXmax) ? validXmax : E;

				int left = local_prev[W];
				int up = local_prev[tx];
				int right = local_prev[E];
				int shortest = MIN(left, up);
				shortest = MIN(shortest, right);

				int xidx = blkX+tx;
				int index = cols*(startStep+i)+xidx;
				local_result[tx] = shortest + gpuWall[index];

				if (tx==11 && i==0)
				{
					int bufIndex = gpuSrc[xidx];
					if (bufIndex >= 0 && bufIndex < 16384) {
						outputBuffer[bufIndex] = 1;
					}
				}
			}
		}
		// Barrier

		if(i==iteration-1)
		{
			break;
		}

		// Update prev from result for computed threads
		for (tx = 0; tx < BLOCK_SIZE; tx++) {
			if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && IN_RANGE(tx, validXmin, validXmax) )
			{
				local_prev[tx] = local_result[tx];
			}
		}
		// Barrier
	}

	// Write results back to global memory
	for (tx = 0; tx < BLOCK_SIZE; tx++) {
		int xidx = blkX+tx;
		if (IN_RANGE(xidx, 0, cols-1)) {
			if( IN_RANGE(tx, validXmin, validXmax) ) {
				// Check if this thread computed something in the last iteration
				if (IN_RANGE(tx, iteration-1+1, BLOCK_SIZE-(iteration-1)-2)) {
					gpuResults[xidx] = local_result[tx];
				}
			}
		}
	}
}

int main(int argc, char** argv)
{
	init(argc, argv);

	int borderCols = (pyramid_height) * HALO;

	int size = rows * cols;

#ifdef  TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

#ifdef  TIMING
	gettimeofday(&tv_init_end, NULL);
	tvsub(&tv_init_end, &tv_total_start, &tv);
	init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    int* h_outputBuffer = (int*)malloc(16384 * sizeof(int));
    for (int i = 0; i < 16384; i++) {
        h_outputBuffer[i] = 0;
	}

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    // Simulate GPU memory buffers
    int* d_gpuWall = new int[size - cols];
    int* d_gpuResult0 = new int[cols];
    int* d_gpuResult1 = new int[cols];

    // Copy data to simulated GPU buffers
    for (int i = 0; i < size - cols; i++) {
        d_gpuWall[i] = data[i + cols];
    }
    for (int i = 0; i < cols; i++) {
        d_gpuResult0[i] = data[i];
        d_gpuResult1[i] = 0;
    }

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
    // Simulate H2D time (negligible in this translation)
    h2d_time = 0.0;
#endif

	int src = 1, final_ret = 0;

	// Determine block size: in OpenCL it was derived from kernel work group info.
	// We'll use a reasonable default or derive from cols.
	// In the original, lwsize was determined by clGetKernelWorkGroupInfo.
	// For translation, we assume a block size of 256 or less, adjusted to fit cols.
	int BLOCK_SIZE = 256;
	if (BLOCK_SIZE > cols) BLOCK_SIZE = cols;
	// Ensure BLOCK_SIZE is large enough for pyramid_height
	if (BLOCK_SIZE < pyramid_height * 2 + 2) {
		BLOCK_SIZE = pyramid_height * 2 + 2;
		if (BLOCK_SIZE > cols) BLOCK_SIZE = cols;
	}

	int num_blocks = (cols + borderCols * 2) / (BLOCK_SIZE - pyramid_height * 2) + 1;
	if (num_blocks * (BLOCK_SIZE - pyramid_height * 2) < cols + borderCols * 2) {
		num_blocks++;
	}
	// Simpler: just cover cols
	num_blocks = (cols + borderCols * 2 + BLOCK_SIZE - 1) / BLOCK_SIZE;
	if (num_blocks == 0) num_blocks = 1;

	for (int t = 0; t < rows - 1; t += pyramid_height)
	{
		int temp = src;
		src = final_ret;
		final_ret = temp;

		int arg0 = MIN(pyramid_height, rows-t-1);
		int theHalo = HALO;

		int* current_src = (src == 0) ? d_gpuResult0 : d_gpuResult1;
		int* current_dest = (final_ret == 0) ? d_gpuResult0 : d_gpuResult1;

#ifdef TIMING
		gettimeofday(&tv_kernel_start, NULL);
#endif

		// Parallelize over blocks
		#pragma omp parallel for
		for (int bx = 0; bx < num_blocks; bx++) {
			LocalBuffers local(BLOCK_SIZE);
			dynproc_kernel(arg0,
						   d_gpuWall,
						   current_src,
						   current_dest,
						   cols,
						   rows,
						   t,
						   borderCols,
						   theHalo,
						   local.prev,
						   local.result,
						   h_outputBuffer,
						   BLOCK_SIZE,
						   bx);
		}

#ifdef TIMING
		gettimeofday(&tv_kernel_end, NULL);
		tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
		kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif
	}

#ifdef TIMING
    // Simulate D2H time
    d2h_time = 0.0;
#endif

	// Copy result back
	for (int i = 0; i < cols; i++) {
		result[i] = (final_ret == 0) ? d_gpuResult0[i] : d_gpuResult1[i];
	}

#ifdef BENCH_PRINT
	for (int i = 0; i < cols; i++)
		printf("%d ", data[i]);
	printf("\n");
	for (int i = 0; i < cols; i++)
		printf("%d ", result[i]);
	printf("\n");
#endif

#ifdef  TIMING
	gettimeofday(&tv_close_start, NULL);
#endif

	delete[] d_gpuWall;
	delete[] d_gpuResult0;
	delete[] d_gpuResult1;
	free(h_outputBuffer);

#ifdef  TIMING
	gettimeofday(&tv_close_end, NULL);
	tvsub(&tv_close_end, &tv_close_start, &tv);
	close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	delete[] data;
	delete[] wall;
	delete[] result;

	return EXIT_SUCCESS;
}

