// Helper functions inline to avoid missing headers
typedef float fp;

void fatal(const char *s) {
    fprintf(stderr, "Error: %s\n", s);
    exit(1);
}

void write_graphics(char* filename, fp* input, int data_rows, int data_cols, int major, int data_range) {
    FILE* fid;
    int i, j;
    fid = fopen(filename, "w");
    if( fid == NULL ){
        printf( "The file was not created/opened for writing\n" );
        return;
    }
    fprintf(fid, "P2\n");
    fprintf(fid, "%d %d\n", data_cols, data_rows);
    fprintf(fid, "%d\n", data_range);
    if(major==0){
        for(i=0; i<data_rows; i++){
            for(j=0; j<data_cols; j++){
                fprintf(fid, "%d ", (int)input[i*data_cols+j]);
            }
            fprintf(fid, "\n");
        }
    } else {
        for(i=0; i<data_rows; i++){
            for(j=0; j<data_cols; j++){
                fprintf(fid, "%d ", (int)input[j*data_rows+i]);
            }
            fprintf(fid, "\n");
        }
    }
    fclose(fid);
}

void read_graphics(char* filename, fp* input, int data_rows, int data_cols, int major) {
    FILE* fid;
    int i, j;
    char c;
    int temp;
    fid = fopen(filename, "r");
    if( fid == NULL ){
        printf( "The file was not opened for reading\n" );
        return;
    }
    i = 0;
    while(i<3){
        c = fgetc(fid);
        if(c == '\n'){
            i = i+1;
        }
    };
    if(major==0){
        for(i=0; i<data_rows; i++){
            for(j=0; j<data_cols; j++){
                fscanf(fid, "%d", &temp);
                input[i*data_cols+j] = (fp)temp;
            }
        }
    } else {
        for(i=0; i<data_rows; i++){
            for(j=0; j<data_cols; j++){
                fscanf(fid, "%d", &temp);
                input[j*data_rows+i] = (fp)temp;
            }
        }
    }
    fclose(fid);
}

void resize(fp* input, int input_rows, int input_cols, fp* output, int output_rows, int output_cols, int major) {
    int i, j;
    int i2, j2;
    if(major == 0){
        for(i=0, i2=0; i<output_rows; i++, i2++){
            if(i2>=input_rows){ i2 = i2 - input_rows; }
            for(j=0, j2=0; j<output_cols; j++, j2++){
                if(j2>=input_cols){ j2 = j2 - input_cols; }
                output[i*output_cols+j] = input[i2*input_cols+j2];
            }
        }
    } else {
        for(j=0, j2=0; j<output_cols; j++, j2++){
            if(j2>=input_cols){ j2 = j2 - input_cols; }
            for(i=0, i2=0; i<output_rows; i++, i2++){
                if(i2>=input_rows){ i2 = i2 - input_rows; }
                output[j*output_rows+i] = input[j2*input_rows+i2];
            }
        }
    }
}

// Kernel implementations
void extract_kernel(long d_Ne, fp* d_I) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        d_I[ei] = exp(d_I[ei]/255);
    }
}

void prepare_kernel(long d_Ne, fp* d_I, fp* d_sums, fp* d_sums2) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        d_sums[ei] = d_I[ei];
        d_sums2[ei] = d_I[ei]*d_I[ei];
    }
}

void reduce_kernel_step(long d_no, int d_mul, fp* d_sums, fp* d_sums2, int blocks_count) {
    // This function simulates one iteration of the reduce_kernel logic
    // It assumes d_sums and d_sums2 contain the input for this reduction step
    // and writes the reduced values back into d_sums/d_sums2 at compressed indices.

    // We need a temporary buffer to hold the partial sums for each block before writing back
    // However, the original algorithm writes directly to d_sums[bx*d_mul*NUMBER_THREADS].
    // Since blocks run in parallel, we must ensure no overlap or use a temp buffer.
    // The original code writes to distinct locations based on bx, so it is safe if we map bx correctly.

    int nt = NUMBER_THREADS;

    #pragma omp parallel
    {
        fp* d_psum = (fp*)malloc(sizeof(fp) * nt);
        fp* d_psum2 = (fp*)malloc(sizeof(fp) * nt);

        int bx = omp_get_thread_num();
        int total_threads = omp_get_num_threads();

        // Map OpenMP threads to OpenCL blocks logic
        // In OpenCL, every block runs this code. In OpenMP, we iterate over blocks.
        // To strictly follow the parallel structure, we should loop over blocks within parallel region
        // or use parallel for over blocks.

        // Let's restructure: Parallel for over blocks
    }
    // Redoing with parallel for over blocks to match OpenCL block behavior exactly

    int nf = nt - (blocks_count * nt - d_no);

    #pragma omp parallel for
    for (int bx = 0; bx < blocks_count; bx++) {
        fp d_psum[NUMBER_THREADS];
        fp d_psum2[NUMBER_THREADS];

        int tx;
        // Simulate threads within block
        // Since OpenMP doesn't have explicit local threads per block in the same way,
        // we must loop over the threads for this block or use nested parallelism.
        // Given the complexity of the barrier logic, a serial loop over threads for each block
        // inside a parallel region over blocks is safest, OR we treat the whole thing as a single parallel region
        // mapping (bx, tx) to a global thread index if possible. 
        // However, the barrier logic depends on all threads in a block finishing.
        // The most robust translation for this specific reduction pattern with barriers is:
        // Outer loop over blocks (parallel), Inner loop over threads (serial or parallel with barrier).
        // But OpenMP barriers apply to the whole team.

        // Strategy: Use a single parallel region where we manually manage the "block" and "thread" logic
        // or simpler: Since the reduction is iterative and the number of blocks decreases,
        // we can just execute the block logic sequentially for each block if the number of blocks is small?
        // No, performance matters.

        // Correct approach: The original code runs ALL blocks in parallel.
        // Inside each block, threads synchronize.
        // We can simulate this by having a parallel region where each thread handles one (block, thread) pair?
        // No, number of threads != number of blocks * NUMBER_THREADS necessarily.

        // Alternative: Loop over blocks in parallel. Inside, compute the reduction for that block.
        // The reduction within a block is small (256 elements). We can do it serially or with a small thread team.
        // To preserve exact behavior and barriers:
        // We will use a temporary array for the block's reduction.

        // Actually, looking at the logic, it's a tree reduction within the block.
        // We can implement this serially for each block efficiently since NT=256 is small,
        // OR use OpenMP tasks/barriers.
        // Let's try to map it to a parallel for over blocks, and inside, use a local array and a loop.
        // The "barrier" in OpenCL ensures all threads in the block have loaded data before summing.
        // In a serial simulation of a block, this is implicit.

        // Wait, the original code uses d_sums[ei*d_mul].
        // If we process blocks in parallel, we read from distinct locations?
        // Yes, bx determines the start index.

        // Implementation: Parallel for over blocks. Inside, serial loop over threads to load, then tree reduction.
        // This loses the intra-block parallelism but maintains correctness and inter-block parallelism.
        // Given NT=256, serial reduction is fast.

        // However, to be more "parallel", we could use #pragma omp parallel inside, but overhead might be high.
        // Let's stick to the structure: Parallel over blocks.

        int start_idx = bx * d_mul * nt; // Where result is written? No, result written to bx*d_mul*NUMBER_THREADS
        // Input indices: ei*d_mul where ei = bx*nt + tx.
        // So input range for block bx is [bx*nt*d_mul, (bx*nt+nf)*d_mul] roughly.

        // Load data
        int limit = (bx == blocks_count - 1) ? nf : nt;

        for (tx = 0; tx < limit; tx++) {
            int ei = bx * nt + tx;
            if (ei < d_no) {
                d_psum[tx] = d_sums[ei * d_mul];
                d_psum2[tx] = d_sums2[ei * d_mul];
            }
        }

        // Barrier equivalent: all loads done before sum

        int df = 0;
        if (nf == nt) {
            for (int i = 2; i <= nt; i = 2 * i) {
                for (tx = 0; tx < nt; tx++) {
                    if ((tx + 1) % i == 0) {
                        d_psum[tx] += d_psum[tx - i/2];
                        d_psum2[tx] += d_psum2[tx - i/2];
                    }
                }
                // Barrier equivalent
            }
            d_sums[bx * d_mul * nt] = d_psum[nt - 1];
            d_sums2[bx * d_mul * nt] = d_psum2[nt - 1];
        } else {
            if (bx != (blocks_count - 1)) {
                for (int i = 2; i <= nt; i = 2 * i) {
                    for (tx = 0; tx < nt; tx++) {
                        if ((tx + 1) % i == 0) {
                            d_psum[tx] += d_psum[tx - i/2];
                            d_psum2[tx] += d_psum2[tx - i/2];
                        }
                    }
                }
                d_sums[bx * d_mul * nt] = d_psum[nt - 1];
                d_sums2[bx * d_mul * nt] = d_psum2[nt - 1];
            } else {
                // Last block with partial fill
                for (int i = 2; i <= nt; i = 2 * i) {
                    if (nf >= i) df = i;
                }
                for (int i = 2; i <= df; i = 2 * i) {
                    for (tx = 0; tx < df; tx++) {
                        if ((tx + 1) % i == 0 && tx < df) {
                            d_psum[tx] += d_psum[tx - i/2];
                            d_psum2[tx] += d_psum2[tx - i/2];
                        }
                    }
                }
                if (df > 0) {
                    tx = df - 1;
                    for (int i = bx * nt + df; i < bx * nt + nf; i++) {
                        d_psum[tx] += d_sums[i];
                        d_psum2[tx] += d_sums2[i];
                    }
                    d_sums[bx * d_mul * nt] = d_psum[tx];
                    d_sums2[bx * d_mul * nt] = d_psum2[tx];
                }
            }
        }
    }
}

void srad_kernel(fp d_lambda, int d_Nr, int d_Nc, long d_Ne, int* d_iN, int* d_iS, int* d_jE, int* d_jW, fp* d_dN, fp* d_dS, fp* d_dW, fp* d_dE, fp d_q0sqr, fp* d_c, fp* d_I) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        int row = (ei + 1) % d_Nr - 1;
        int col = (ei + 1) / d_Nr + 1 - 1;
        if ((ei + 1) % d_Nr == 0) {
            row = d_Nr - 1;
            col = col - 1;
        }

        fp d_Jc = d_I[ei];
        fp d_dN_loc = d_I[d_iN[row] + d_Nr * col] - d_Jc;
        fp d_dS_loc = d_I[d_iS[row] + d_Nr * col] - d_Jc;
        fp d_dW_loc = d_I[row + d_Nr * d_jW[col]] - d_Jc;
        fp d_dE_loc = d_I[row + d_Nr * d_jE[col]] - d_Jc;

        fp d_G2 = (d_dN_loc * d_dN_loc + d_dS_loc * d_dS_loc + d_dW_loc * d_dW_loc + d_dE_loc * d_dE_loc) / (d_Jc * d_Jc);
        fp d_L = (d_dN_loc + d_dS_loc + d_dW_loc + d_dE_loc) / d_Jc;

        fp d_num = (0.5 * d_G2) - ((1.0 / 16.0) * (d_L * d_L));
        fp d_den = 1 + (0.25 * d_L);
        fp d_qsqr = d_num / (d_den * d_den);

        d_den = (d_qsqr - d_q0sqr) / (d_q0sqr * (1 + d_q0sqr));
        fp d_c_loc = 1.0 / (1.0 + d_den);

        if (d_c_loc < 0) d_c_loc = 0;
        else if (d_c_loc > 1) d_c_loc = 1;

        d_dN[ei] = d_dN_loc;
        d_dS[ei] = d_dS_loc;
        d_dW[ei] = d_dW_loc;
        d_dE[ei] = d_dE_loc;
        d_c[ei] = d_c_loc;
    }
}

void srad2_kernel(fp d_lambda, int d_Nr, int d_Nc, long d_Ne, int* d_iN, int* d_iS, int* d_jE, int* d_jW, fp* d_dN, fp* d_dS, fp* d_dE, fp* d_dW, fp* d_c, fp* d_I) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        int row = (ei + 1) % d_Nr - 1;
        int col = (ei + 1) / d_Nr + 1 - 1;
        if ((ei + 1) % d_Nr == 0) {
            row = d_Nr - 1;
            col = col - 1;
        }

        fp d_cN = d_c[ei];
        fp d_cS = d_c[d_iS[row] + d_Nr * col];
        fp d_cW = d_c[ei];
        fp d_cE = d_c[row + d_Nr * d_jE[col]];

        fp d_D = d_cN * d_dN[ei] + d_cS * d_dS[ei] + d_cW * d_dW[ei] + d_cE * d_dE[ei];

        d_I[ei] = d_I[ei] + 0.25 * d_lambda * d_D;
    }
}

void compress_kernel(long d_Ne, fp* d_I) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        d_I[ei] = log(d_I[ei]) * 255;
    }
}

void kernel_gpu_opencl_wrapper(fp* image, int Nr, int Nc, long Ne, int niter, fp lambda, long NeROI, int* iN, int* iS, int* jE, int* jW, int iter, int mem_size_i, int mem_size_j) {
    printf("WG size of kernel = %d \n", NUMBER_THREADS);

    fp* d_I = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_sums = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_sums2 = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dN = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dS = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dW = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dE = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_c = (fp*)malloc(sizeof(fp) * Ne);

    // Copy image to device (simulate)
    memcpy(d_I, image, sizeof(fp) * Ne);

    // Extract
    extract_kernel(Ne, d_I);

    // Prepare
    prepare_kernel(Ne, d_I, d_sums, d_sums2);

    // Reduce loop setup
    int blocks_x = Ne / NUMBER_THREADS;
    if (Ne % NUMBER_THREADS != 0) blocks_x++;
    int blocks_work_size = blocks_x;

    fp total, total2;

    printf("Iterations Progress: hidden\n");

    for (iter = 0; iter < niter; iter++) {
        // Prepare
        prepare_kernel(Ne, d_I, d_sums, d_sums2);

        // Reduce
        long no = Ne;
        int mul = 1;
        int blocks2_work_size = blocks_work_size;

        while (blocks2_work_size != 0) {
            reduce_kernel_step(no, mul, d_sums, d_sums2, blocks2_work_size);

            no = blocks2_work_size;
            if (blocks2_work_size == 1) {
                blocks2_work_size = 0;
            } else {
                mul = mul * NUMBER_THREADS;
                blocks_x = blocks2_work_size / NUMBER_THREADS;
                if (blocks2_work_size % NUMBER_THREADS != 0) blocks_x++;
                blocks2_work_size = blocks_x;
            }
        }

        total = d_sums[0];
        total2 = d_sums2[0];

        fp meanROI = total / (fp)(NeROI);
        fp meanROI2 = meanROI * meanROI;
        fp varROI = (total2 / (fp)(NeROI)) - meanROI2;
        fp q0sqr = varROI / meanROI2;

        // SRAD
        srad_kernel(lambda, Nr, Nc, Ne, iN, iS, jE, jW, d_dN, d_dS, d_dW, d_dE, q0sqr, d_c, d_I);

        // SRAD2
        srad2_kernel(lambda, Nr, Nc, Ne, iN, iS, jE, jW, d_dN, d_dS, d_dW, d_dE, d_c, d_I);
    }
    printf("\n");

    // Compress
    compress_kernel(Ne, d_I);

    // Copy back
    memcpy(image, d_I, sizeof(fp) * Ne);

    free(d_I);
    free(d_sums);
    free(d_sums2);
    free(d_dN);
    free(d_dS);
    free(d_dW);
    free(d_dE);
    free(d_c);
}

int platform_id_inuse = 0;
int device_id_inuse = 0;

int main(int argc, char* argv []) {
    fp* image_ori;
    int image_ori_rows;
    int image_ori_cols;
    long image_ori_elem;

    fp* image;
    int Nr, Nc;
    long Ne;

    int niter;
    fp lambda;

    int r1, r2, c1, c2;
    long NeROI;

    int* iN;
    int* iS;
    int* jE;
    int* jW;

    int iter;
    long i;
    long j;

    int mem_size_i;
    int mem_size_j;

    // Defaults
    niter = 10;
    lambda = 0.5;
    Nr = 256;
    Nc = 256;

    int cur_arg;
    for (cur_arg = 1; cur_arg < argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-n") == 0) {
            if (argc >= cur_arg + 1) {
                niter = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-l") == 0) {
            if (argc >= cur_arg + 1) {
                lambda = (fp)atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-s") == 0) {
            if (argc >= cur_arg + 3) {
                Nr = atoi(argv[cur_arg+1]);
                Nc = atoi(argv[cur_arg+2]);
                cur_arg += 2;
            }
        }
        else if (strcmp(argv[cur_arg], "-p") == 0) {
            if (argc >= cur_arg + 1) {
                platform_id_inuse = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-d") == 0) {
            if (argc >= cur_arg + 1) {
                device_id_inuse = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
    }

    image_ori_rows = 502;
    image_ori_cols = 458;
    image_ori_elem = image_ori_rows * image_ori_cols;

    image_ori = (fp*)malloc(sizeof(fp) * image_ori_elem);

    read_graphics("../../data/srad/image.pgm", image_ori, image_ori_rows, image_ori_cols, 1);

    Ne = (long)Nr * Nc;
    image = (fp*)malloc(sizeof(fp) * Ne);

    resize(image_ori, image_ori_rows, image_ori_cols, image, Nr, Nc, 1);

    r1 = 0;
    r2 = Nr - 1;
    c1 = 0;
    c2 = Nc - 1;

    NeROI = (long)(r2 - r1 + 1) * (c2 - c1 + 1);

    mem_size_i = sizeof(int) * Nr;
    iN = (int *)malloc(mem_size_i);
    iS = (int *)malloc(mem_size_i);
    mem_size_j = sizeof(int) * Nc;
    jW = (int *)malloc(mem_size_j);
    jE = (int *)malloc(mem_size_j);

    for (i = 0; i < Nr; i++) {
        iN[i] = i - 1;
        iS[i] = i + 1;
    }
    for (j = 0; j < Nc; j++) {
        jW[j] = j - 1;
        jE[j] = j + 1;
    }

    iN[0] = 0;
    iS[Nr-1] = Nr-1;
    jW[0] = 0;
    jE[Nc-1] = Nc-1;

    kernel_gpu_opencl_wrapper(image, Nr, Nc, Ne, niter, lambda, NeROI, iN, iS, jE, jW, iter, mem_size_i, mem_size_j);

    write_graphics("./output/image_out.pgm", image, Nr, Nc, 1, 255);

    free(image_ori);
    free(image);
    free(iN);
    free(iS);
    free(jW);
    free(jE);

    return 0;
}

