#ifdef INSERT_WASTE
float waste(float s )
{
  for( int i =0 ; i< 4; i++ ) {
    s += pow(s,0.78);
  }
  return s;
}
#endif

float dist(Point p1, Point p2, int dim)
{
  int i;
  float result=0.0;
  for (i=0;i<dim;i++)
    result += (p1.coord[i] - p2.coord[i])*(p1.coord[i] - p2.coord[i]);
#ifdef INSERT_WASTE
  float s = waste(result);
  result += s;
  result -= s;
#endif
  return(result);
}

float pspeedy(Points *points, float z, long *kcenter, int pid, pthread_barrier_t* barrier)
{
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
cnt_speedy++;
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  long bsize = points->num/nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if( pid == nproc-1 ) k2 = points->num;
  static float totalcost;

  static bool open = false;
  static float* costs; 
  static int i;

#ifdef ENABLE_THREADS
  static pthread_mutex_t mutex = PTHREAD_MUTEX_INITIALIZER;
  static pthread_cond_t cond = PTHREAD_COND_INITIALIZER;
#endif

#ifdef PRINTINFO
  if( pid == 0 ){
    fprintf(stderr, "Speedy: facility cost %lf\n", z);
  }
#endif

  for( int k = k1; k < k2; k++ )    {
    float distance = dist(points->p[k],points->p[0],points->dim);
    points->p[k].cost = distance * points->p[k].weight;
    points->p[k].assign=0;
  }

  if( pid==0 )   {
    *kcenter = 1;
    costs = (float*)malloc(sizeof(float)*nproc);
  }

  if( pid != 0 ) { 
    while(1) {
#ifdef ENABLE_THREADS
      pthread_mutex_lock(&mutex);
      while(!open) pthread_cond_wait(&cond,&mutex);
      pthread_mutex_unlock(&mutex);
#endif
      if( i >= points->num ) break;
      for( int k = k1; k < k2; k++ )
	{
	  float distance = dist(points->p[i],points->p[k],points->dim);
	  if( distance*points->p[k].weight < points->p[k].cost )
	    {
	      points->p[k].cost = distance * points->p[k].weight;
	      points->p[k].assign=i;
	    }
	}
#ifdef ENABLE_THREADS
      pthread_barrier_wait(barrier);
      pthread_barrier_wait(barrier);
#endif
    } 
  }
  else  { 
    for(i = 1; i < points->num; i++ )  {
      bool to_open = ((float)lrand48()/(float)INT_MAX)<(points->p[i].cost/z); 
      if( to_open )  {
	(*kcenter)++;
#ifdef ENABLE_THREADS
	pthread_mutex_lock(&mutex);
#endif
	open = true;
#ifdef ENABLE_THREADS
	pthread_mutex_unlock(&mutex);
	pthread_cond_broadcast(&cond);
#endif
	for( int k = k1; k < k2; k++ )  {	
	  float distance = dist(points->p[i],points->p[k],points->dim);
	  if( distance*points->p[k].weight < points->p[k].cost )  {
	    points->p[k].cost = distance * points->p[k].weight;
	    points->p[k].assign=i;
	  }
	}
#ifdef ENABLE_THREADS
	pthread_barrier_wait(barrier);
#endif
	open = false;
#ifdef ENABLE_THREADS
	pthread_barrier_wait(barrier);
#endif
      }
    }
#ifdef ENABLE_THREADS
    pthread_mutex_lock(&mutex);
#endif
    open = true;
#ifdef ENABLE_THREADS
    pthread_mutex_unlock(&mutex);
    pthread_cond_broadcast(&cond);
#endif
  }
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif
  open = false;
  float mytotal = 0;
  for( int k = k1; k < k2; k++ )  {
    mytotal += points->p[k].cost;
  }
  costs[pid] = mytotal;
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  if( pid == 0 )
    {
      totalcost=z*(*kcenter);
      for( int i = 0; i < nproc; i++ )
	{
	  totalcost += costs[i];
	} 
      free(costs);
    }
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

#ifdef PRINTINFO
  if( pid == 0 )
    {
      fprintf(stderr, "Speedy opened %d facilities for total cost %lf\n",
	      *kcenter, totalcost);
      fprintf(stderr, "Distance Cost %lf\n", totalcost - z*(*kcenter));
    }
#endif

#ifdef PROFILE_TMP
  double t2 = gettime();
  if( pid== 0 ) {
    time_speedy += t2 -t1;
  }
#endif
  return(totalcost);
}

typedef struct {
  float weight;
  long assign;  
  float cost;  
} Point_Struct;

void pgain_kernel_impl(
    Point_Struct *p,
    float *coord_d,
    float * work_mem_d,
    int *center_table_d,
    char *switch_membership_d,
    int num,
    int dim,
    long x,
    int K) {

    #pragma omp parallel
    {
        // Local memory simulation per thread (or shared for simplicity if num is large enough to avoid contention, 
        // but strictly following OpenCL logic requires per-thread coord_s or careful synchronization)
        // Since OpenMP threads don't have explicit local memory like OpenCL, we use a local array.
        // To avoid race conditions on coord_s if multiple threads run simultaneously, 
        // we must ensure only one thread populates it or replicate it.
        // The original code uses local_id == 0 to populate, then barrier.
        // In OpenMP, we can just load it once per thread or use a shared variable with a single region.

        float coord_s[dim];

        #pragma omp single
        {
            for(int i=0; i<dim; i++){ 
                coord_s[i] = coord_d[i*num + x];
            }
        }
        // Implicit barrier at end of single region

        int thread_id = omp_get_thread_num();
        // We need to iterate over all points, not just one per thread, because the original kernel
        // maps global_id to thread_id < num. In OpenMP parallel for, we distribute the loop.

        #pragma omp for
        for(int t_id = 0; t_id < num; t_id++) {
            float x_cost = 0.0;
            for(int i=0; i<dim; i++)
                x_cost += (coord_d[(i*num)+t_id]-coord_s[i]) * (coord_d[(i*num)+t_id]-coord_s[i]);
            x_cost = x_cost * p[t_id].weight;

            float current_cost = p[t_id].cost;

            int base = t_id*(K+1);	 

            if ( x_cost < current_cost ){
                switch_membership_d[t_id] = '1';
                int addr_1 = base + K;
                work_mem_d[addr_1] = x_cost - current_cost;
            }
            else {
                int assign = p[t_id].assign;
                int addr_2 = base + center_table_d[assign];
                work_mem_d[addr_2] += current_cost - x_cost;
            }
        }
    }
}

float pgain(long x, Points *points, float z, long *numcenters, int kmax, bool *is_center, int *center_table, char *switch_membership,
            double *serial, double *cpu_gpu_memcpy, double *memcpy_back, double *gpu_malloc, double *kernel) {

    // Note: The original pgain uses OpenCL for the inner loop. 
    // We replace the OpenCL invocation with the OpenMP implementation.
    // The memory management (allocDevMem, etc.) from the header file 3 is removed/replaced 
    // as we are now purely using host memory with OpenMP.

    int K = *numcenters;
    int num = points->num;
    int dim = points->dim;
    int effective_kmax = kmax + 1;

    // Prepare center_table
    int count = 0;
    for(int i=0; i<num; i++){
        if(is_center[i])
            center_table[i] = count++;
    }

    // Allocate working memory
    // work_mem_d in OpenCL was size (K+1)*num. 
    // We use a raw array here.
    float *work_mem = (float*)calloc((K+1)*num, sizeof(float));
    if (!work_mem) {
        fprintf(stderr, "Memory allocation failed\n");
        exit(1);
    }

    // Prepare p array (Point_Struct)
    Point_Struct *p_arr = (Point_Struct*)malloc(num * sizeof(Point_Struct));
    for(int i=0; i<num; i++){
        p_arr[i].weight = points->p[i].weight;
        p_arr[i].assign = points->p[i].assign;
        p_arr[i].cost = points->p[i].cost;
    }

    // Prepare coord array (dim * num)
    float *coord_arr = (float*)malloc(dim * num * sizeof(float));
    for(int i=0; i<dim; i++){
        for(int j=0; j<num; j++)
            coord_arr[i*num + j] = points->p[j].coord[i];
    }

    // Reset switch_membership
    memset(switch_membership, 0, num * sizeof(char));

    double t_start = gettime();

    // Call OpenMP version of the kernel
    pgain_kernel_impl(p_arr, coord_arr, work_mem, center_table, switch_membership, num, dim, x, K);

    double t_end = gettime();
    *kernel += t_end - t_start;

    // Process results (same logic as original pgain after kernel execution)
    float *gl_lower = (float*)calloc(kmax, sizeof(float));

    int numclose = 0;
    float gl_cost = z;

    for(int i=0; i < num; i++){	
        if( is_center[i] ) {
            float low = z;
            for( int j = 0; j < num; j++ )
                low += work_mem[ j*(K+1) + center_table[i] ];

            gl_lower[center_table[i]] = low;

            if ( low > 0 ) {
                numclose++;				
                work_mem[i*(K+1)+K] -= low;
            }
        }
        gl_cost += work_mem[i*(K+1)+K];
    }

    float result_cost = 0.0;

    if ( gl_cost < 0 ) {
        for(int i=0; i<num; i++){
            bool close_center = gl_lower[center_table[points->p[i].assign]] > 0 ;
            if ( (switch_membership[i]=='1') || close_center ) {
                points->p[i].cost = points->p[i].weight * dist(points->p[i], points->p[x], points->dim);
                points->p[i].assign = x;
            }
        }

        for(int i=0; i<num; i++){
            if( is_center[i] && gl_lower[center_table[i]] > 0 )
                is_center[i] = false;
        }

        is_center[x] = true;
        *numcenters = *numcenters + 1 - numclose;
        result_cost = -gl_cost;
    }
    else {
        result_cost = 0.0;
    }

    free(work_mem);
    free(p_arr);
    free(coord_arr);
    free(gl_lower);

    return result_cost;
}

float pFL(Points *points, int *feasible, int numfeasible,
	  float z, long *k, int kmax, float cost, long iter, float e, 
	  int pid, pthread_barrier_t* barrier)
{
#ifdef PROFILE_TMP
	double t1 = gettime();
#endif
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif
  long i;
  long x;
  float change;
  long numberOfPoints;

  change = cost;

  while (change/cost > 1.0*e) {
    change = 0.0;
    numberOfPoints = points->num;

    if( pid == 0 ) {
      intshuffle(feasible, numfeasible);
    }
#ifdef ENABLE_THREADS
    pthread_barrier_wait(barrier);
#endif
    for (i=0;i<iter;i++) {
	    x = i%numfeasible;

	    change += pgain(feasible[x], points, z, k, kmax, is_center, center_table, switch_membership,
												&serial, &cpu_gpu_memcpy, &memcpy_back, &gpu_malloc, &kernel);
    }		
    cost -= change;
#ifdef PRINTINFO
    if( pid == 0 ) {
      fprintf(stderr, "%d centers, cost %lf, total distance %lf\n",
	      *k, cost, cost - z*(*k));
    }
#endif
#ifdef ENABLE_THREADS
    pthread_barrier_wait(barrier);
#endif
  }
#ifdef PROFILE_TMP
	double t2 = gettime();
	time_FL += t2 - t1;
#endif
  return(cost);
}

int selectfeasible_fast(Points *points, int **feasible, int kmin, int pid, pthread_barrier_t* barrier)
{
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif

  int numfeasible = points->num;
  if (numfeasible > (ITER*kmin*log((float)kmin)))
    numfeasible = (int)(ITER*kmin*log((float)kmin));
  *feasible = (int *)malloc(numfeasible*sizeof(int));

  float* accumweight;
  float totalweight;

  long k1 = 0;
  long k2 = numfeasible;

  float w;
  int l,r,k;

  if (numfeasible == points->num) {
    for (int i=k1;i<k2;i++)
      (*feasible)[i] = i;
    return numfeasible;
  }

  accumweight= (float*)malloc(sizeof(float)*points->num);
  accumweight[0] = points->p[0].weight;
  totalweight=0;
  for( int i = 1; i < points->num; i++ ) {
    accumweight[i] = accumweight[i-1] + points->p[i].weight;
  }
  totalweight=accumweight[points->num-1];

  for(int i=k1; i<k2; i++ ) {
    w = (lrand48()/(float)INT_MAX)*totalweight;

    l=0;
    r=points->num-1;
    if( accumweight[0] > w )  { 
      (*feasible)[i]=0; 
      continue;
    }
    while( l+1 < r ) {
      k = (l+r)/2;
      if( accumweight[k] > w ) {
	r = k;
      } 
      else {
	l=k;
      }
    }
    (*feasible)[i]=r;
  }
  free(accumweight); 
#ifdef PROFILE_TMP
  double t2 = gettime();
  time_select_feasible += t2-t1;
#endif
  return numfeasible;
}

float pkmedian(Points *points, long kmin, long kmax, long* kfinal,
	       int pid, pthread_barrier_t* barrier )
{
  int i;
  float cost;
  float lastcost;
  float hiz, loz, z;

  static long k;
  static int *feasible;
  static int numfeasible;
  static float* hizs;

  if( pid==0 ) hizs = (float*)calloc(nproc,sizeof(float));
  hiz = loz = 0.0;
  long numberOfPoints = points->num;
  long ptDimension = points->dim;

  long bsize = points->num/nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if( pid == nproc-1 ) k2 = points->num;

#ifdef PRINTINFO
  if( pid == 0 )
    {
      printf("Starting Kmedian procedure\n");
      printf("%i points in %i dimensions\n", numberOfPoints, ptDimension);
    }
#endif

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  float myhiz = 0;
  for (long kk=k1;kk < k2; kk++ ) {
    myhiz += dist(points->p[kk], points->p[0],
		      ptDimension)*points->p[kk].weight;
  }
  hizs[pid] = myhiz;

#ifdef ENABLE_THREADS  
  pthread_barrier_wait(barrier);
#endif

  for( int i = 0; i < nproc; i++ )   {
    hiz += hizs[i];
  }

  loz=0.0; z = (hiz+loz)/2.0;

  if (points->num <= kmax) {	
    for (long kk=k1;kk<k2;kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    cost = 0;
    if( pid== 0 ) {
      free(hizs); 
      *kfinal = k;
    }
    return cost;
  }

  if( pid == 0 ) shuffle(points);	
  cost = pspeedy(points, z, &k, pid, barrier);
#ifdef PRINTINFO
  if( pid == 0 )
    printf("thread %d: Finished first call to speedy, cost=%lf, k=%i\n",pid,cost,k);
#endif
  i=0;

  while ((k < kmin)&&(i<SP)) {
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

#ifdef PRINTINFO
  if( pid==0)
    printf("thread %d: second call to speedy, cost=%lf, k=%d\n",pid,cost,k);
#endif 

  while (k < kmin) {
#ifdef PRINTINFO
    if( pid == 0 ) {
      printf("%lf %lf\n", loz, hiz);
      printf("Speedy indicates we should try lower z\n");
    }
#endif
    if (i >= SP) {hiz=z; z=(hiz+loz)/2.0; i=0;}
    if( pid == 0 ) shuffle(points);
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

  if( pid == 0 )
    {
      numfeasible = selectfeasible_fast(points,&feasible,kmin,pid,barrier); 
      for( int i = 0; i< points->num; i++ ) {
	is_center[points->p[i].assign]= true;
      }
    }

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  while(1) {
#ifdef PRINTINFO
    if( pid==0 )
      {
	printf("loz = %lf, hiz = %lf\n", loz, hiz);
	printf("Running Local Search...\n");
      }
#endif

    lastcost = cost;
    cost = pFL(points, feasible, numfeasible,
	       z, &k, kmax, cost, (long)(ITER*kmax*log((float)kmax)), 0.1, pid, barrier);

    if (((k <= (1.1)*kmax)&&(k >= (0.9)*kmin))||
	((k <= kmax+2)&&(k >= kmin-2))) {
#ifdef PRINTINFO
      if( pid== 0)
	{
	  printf("Trying a more accurate local search...\n");
	}
#endif
      cost = pFL(points, feasible, numfeasible,
		 z, &k, kmax, cost, (long)(ITER*kmax*log((float)kmax)), 0.001, pid, barrier);
    }

    if (k > kmax) {
      loz = z; z = (hiz+loz)/2.0;
      cost += (z-loz)*k;
    }
    if (k < kmin) {
      hiz = z; z = (hiz+loz)/2.0;
      cost += (z-hiz)*k;
    }

    if (((k <= kmax)&&(k >= kmin))||((loz >= (0.999)*hiz)) )
      { 
	break;
      }
#ifdef ENABLE_THREADS
    pthread_barrier_wait(barrier);
#endif
  }

  if( pid==0 ) {
    free(feasible); 
    free(hizs);
    *kfinal = k;
  }

  return cost;
}

int contcenters(Points *points)
{
  long i, ii;
  float relweight;

  for (i=0;i<points->num;i++) {
    if (points->p[i].assign != i) {
      relweight=points->p[points->p[i].assign].weight + points->p[i].weight;
      relweight = points->p[i].weight/relweight;
      for (ii=0;ii<points->dim;ii++) {
        points->p[points->p[i].assign].coord[ii]*=1.0-relweight;
        points->p[points->p[i].assign].coord[ii]+= points->p[i].coord[ii]*relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }
  return 0;
}

void copycenters(Points *points, Points* centers, long* centerIDs, long offset)
{
  long i;
  long k;
  bool *is_a_median = (bool *) calloc(points->num, sizeof(bool));

  for ( i = 0; i < points->num; i++ ) {
    is_a_median[points->p[i].assign] = 1;
  }

  k=centers->num;
  for ( i = 0; i < points->num; i++ ) {
    if ( is_a_median[i] ) {
      memcpy( centers->p[k].coord, points->p[i].coord, points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }
  centers->num = k;
  free(is_a_median);
}

void* localSearchSub(void* arg_) {
  pkmedian_arg_t* arg= (pkmedian_arg_t*)arg_;
  pkmedian(arg->points,arg->kmin,arg->kmax,arg->kfinal,arg->pid,arg->barrier);
  return NULL;
}

void localSearch( Points* points, long kmin, long kmax, long* kfinal ) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif

  pthread_barrier_t barrier;
#ifdef ENABLE_THREADS
  pthread_barrier_init(&barrier,NULL,nproc);
#endif
  pthread_t* threads = new pthread_t[nproc];
  pkmedian_arg_t* arg = new pkmedian_arg_t[nproc];

  for( int i = 0; i < nproc; i++ ) {
    arg[i].points = points;
    arg[i].kmin = kmin;
    arg[i].kmax = kmax;
    arg[i].pid = i;
    arg[i].kfinal = kfinal;
    arg[i].barrier = &barrier;
#ifdef ENABLE_THREADS
    pthread_create(threads+i,NULL,localSearchSub,(void*)&arg[i]);
#else
    localSearchSub(&arg[0]);
#endif
  }

  for ( int i = 0; i < nproc; i++) {
#ifdef ENABLE_THREADS
    pthread_join(threads[i],NULL);
#endif
  }

  delete[] threads;
  delete[] arg;
#ifdef ENABLE_THREADS
  pthread_barrier_destroy(&barrier);
#endif

#ifdef PROFILE_TMP
  double t2 = gettime();
  time_local_search += t2-t1;
#endif
}

void outcenterIDs( Points* centers, long* centerIDs, char* outfile ) {
  FILE* fp = fopen(outfile, "w");
  if( fp==NULL ) {
    fprintf(stderr, "error opening %s\n",outfile);
    exit(1);
  }
  int* is_a_median = (int*)calloc( sizeof(int), centers->num );
  for( int i =0 ; i< centers->num; i++ ) {
    is_a_median[centers->p[i].assign] = 1;
  }

  for( int i = 0; i < centers->num; i++ ) {
    if( is_a_median[i] ) {
      fprintf(fp, "%ld\n", centerIDs[i]);
      fprintf(fp, "%lf\n", centers->p[i].weight);
      for( int k = 0; k < centers->dim; k++ ) {
	fprintf(fp, "%lf ", centers->p[i].coord[k]);
      }
      fprintf(fp,"\n\n");
    }
  }
  fclose(fp);
}

void streamCluster( PStream* stream, 
		    long kmin, long kmax, int dim,
		    long chunksize, long centersize, char* outfile )
{
  float* block = (float*)malloc( chunksize*dim*sizeof(float) );
  float* centerBlock = (float*)malloc(centersize*dim*sizeof(float) );
  long* centerIDs = (long*)malloc(centersize*sizeof(long));

  if( block == NULL ) { 
    fprintf(stderr,"not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  points.p = (Point *)malloc(chunksize*sizeof(Point));
  for( int i = 0; i < chunksize; i++ ) {
    points.p[i].coord = &block[i*dim];		
  }

  Points centers;
  centers.dim = dim;
  centers.p = (Point *)malloc(centersize*sizeof(Point));
  centers.num = 0;

  for( int i = 0; i< centersize; i++ ) {
    centers.p[i].coord = &centerBlock[i*dim];
    centers.p[i].weight = 1.0;
  }

  long IDoffset = 0;
  long kfinal;
  while(1) {
    size_t numRead  = stream->read(block, dim, chunksize ); 
    fprintf(stderr,"read %lu points\n",numRead);

    if( stream->ferror() || numRead < (unsigned int)chunksize && !stream->feof() ) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = numRead;
    for( int i = 0; i < points.num; i++ ) {
      points.p[i].weight = 1.0;
    }

    switch_membership = (char*)malloc(points.num*sizeof(char));
    is_center = (bool*)calloc(points.num,sizeof(bool));
    center_table = (int*)malloc(points.num*sizeof(int));

    localSearch(&points,kmin, kmax,&kfinal);

    fprintf(stderr,"finish local search\n");
    contcenters(&points);
    if( kfinal + centers.num > centersize ) {
      fprintf(stderr,"oops! no more space for centers\n");
      exit(1);
    }

#ifdef PRINTINFO
    printf("finish cont center\n");
#endif

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset += numRead;

#ifdef PRINTINFO
    printf("finish copy centers\n"); 
#endif
    free(is_center);
    free(switch_membership);
    free(center_table);
    if( stream->feof() ) {
      break;
    }
  }

  switch_membership = (char*)malloc(centers.num*sizeof(char));
  is_center = (bool*)calloc(centers.num,sizeof(bool));
  center_table = (int*)malloc(centers.num*sizeof(int));

  localSearch( &centers, kmin, kmax ,&kfinal );
  contcenters(&centers);
  outcenterIDs( &centers, centerIDs, outfile);

  free(block);
  free(centerBlock);
  free(centerIDs);
  free(points.p);
  free(centers.p);
}

int main(int argc, char **argv)
{
  char *outfilename = new char[MAXNAMESIZE];
  char *infilename = new char[MAXNAMESIZE];
  long kmin, kmax, n, chunksize, clustersize;
  int dim;

#ifdef PARSEC_VERSION
#define __PARSEC_STRING(x) #x
#define __PARSEC_XSTRING(x) __PARSEC_STRING(x)
  printf("PARSEC Benchmark Suite Version "__PARSEC_XSTRING(PARSEC_VERSION)"\n");
  fflush(NULL);
#else
  printf("PARSEC Benchmark Suite\n");
  fflush(NULL);
#endif 

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_begin(__parsec_streamcluster);
#endif

  if (argc<11) {
    fprintf(stderr,"usage: %s k1 k2 d n chunksize clustersize infile outfile nproc [-p platform] [-d device]\n",
	    argv[0]);
    fprintf(stderr,"  k1:          Min. number of centers allowed\n");
    fprintf(stderr,"  k2:          Max. number of centers allowed\n");
    fprintf(stderr,"  d:           Dimension of each data point\n");
    fprintf(stderr,"  n:           Number of data points\n");
    fprintf(stderr,"  chunksize:   Number of data points to handle per step\n");
    fprintf(stderr,"  clustersize: Maximum number of intermediate centers\n");
    fprintf(stderr,"  infile:      Input file (if n<=0)\n");
    fprintf(stderr,"  outfile:     Output file\n");
    fprintf(stderr,"  nproc:       Number of threads to use\n");
    fprintf(stderr,"  platform:    Platform id\n");
    fprintf(stderr,"  device:      Device id\n");
    fprintf(stderr,"\n");
    fprintf(stderr, "if n > 0, points will be randomly generated instead of reading from infile.\n");
    exit(1);
  }
  kmin = atoi(argv[1]);
  kmax = atoi(argv[2]);
  dim = atoi(argv[3]);
  n = atoi(argv[4]);
  chunksize = atoi(argv[5]);
  clustersize = atoi(argv[6]);
  strcpy(infilename, argv[7]);
  strcpy(outfilename, argv[8]);
  nproc = atoi(argv[9]);

  // Ignore platform/device args for OpenMP version but consume them
  for (int i = 10; i < argc; ++i) {
      if (argv[i][0] == '-') {
          if (i+1 < argc) i++;
      }
  }

#ifdef  TIMING
  struct timeval tv_total_start, tv_total_end;
  struct timeval tv;
  float init_time = 0, close_time = 0, total_time = 0;
  gettimeofday(&tv_total_start, NULL);
#endif

  srand48(SEED);
  PStream* stream;
  if( n > 0 ) {
    stream = new SimStream(n);
  }
  else {
    stream = new FileStream(infilename);
  }
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_begin();
#endif
#ifdef PROFILE_TMP
  serial = 0.0;
  cpu_gpu_memcpy = 0.0;
  gpu_malloc = 0.0;
  gpu_free = 0.0;
  kernel = 0.0;
  time_FL = 0.0;
  cnt_speedy = 0;
#endif
  std::cout<<"before sc"<<std::endl;
  streamCluster(stream, kmin, kmax, dim, chunksize, clustersize, outfilename );
  std::cout<<"after sc"<<std::endl;
#ifdef PROFILE_TMP 
  gpu_free = gettime();
#endif
#ifdef  TIMING
  gettimeofday(&tv_close_start, NULL);
#endif

#ifdef PROFILE_TMP
  gpu_free = gettime() - gpu_free;
#endif

#ifdef  TIMING
  gettimeofday(&tv_close_end, NULL);
  tvsub(&tv_close_end, &tv_close_start, &tv);
  close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_end();
#endif

#ifdef PROFILE_TMP
  double t2 = gettime();
  printf("time = %lf\n",t2-t1);
#endif

  delete stream;

#ifdef  TIMING
  tvsub(&tv_close_end, &tv_total_start, &tv);
  total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

  printf("Init: %f\n", init_time);
  printf("Close: %f\n", close_time);
  printf("Total: %f\n", total_time);
#endif

#ifdef PROFILE_TMP
  printf("time pgain = %lf\n", time_gain);
  printf("time pgain_dist = %lf\n", time_gain_dist);
  printf("time pgain_init = %lf\n", time_gain_init);
  printf("time pselect = %lf\n", time_select_feasible);
  printf("time pspeedy = %lf\n", time_speedy);
  printf("time pshuffle = %lf\n", time_shuffle);
  printf("time FL = %lf\n", time_FL);
  printf("time localSearch = %lf\n", time_local_search);
  printf("\n");
  printf("====GPU Timing info====\n");
  printf("time serial = %lf\n", serial);
  printf("time CPU to GPU memory copy = %lf\n", cpu_gpu_memcpy);
  printf("time GPU to CPU memory copy back = %lf\n", memcpy_back);
  printf("time GPU malloc = %lf\n", gpu_malloc);
  printf("time GPU free = %lf\n", gpu_free);
  printf("time kernel = %lf\n", kernel);

  FILE *fp = fopen("PD.txt", "w");
  fprintf(fp, "%lf, %lf, %lf, %lf, %lf, %lf, %lf, %lf, %lf\n", time_FL, cpu_gpu_memcpy, memcpy_back, kernel, gpu_malloc, gpu_free, 0.0);
  fclose(fp);	
#endif

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_end();
#endif

  delete[] outfilename;
  delete[] infilename;

  return 0;
}
